  (() => {
    const inputs = JSON.parse(JSON.stringify($('PROCESSA BRUNA').item.json.inputs || {}));

    function normSaude(v) {
      const s = String(v || '').trim().toLowerCase();

      if (['sim', 'ok', 'em_dia', 'em dia', 'true'].includes(s)) return 'sim';

      if (
        [
          'nao',
          'não',
          'nao_ok',
          'não_ok',
          'atrasado',
          'atrasada',
          'vencido',
          'vencida',
          'pendente',
          'false'
        ].includes(s)
      ) return 'nao';

      return 'nao_informado';
    }

    if (!inputs.resumo_lead) inputs.resumo_lead = {};
    if (!inputs.resumo_interno_repasse) inputs.resumo_interno_repasse = {};

    inputs.resumo_lead.cao_vacinas_ok = normSaude(inputs.resumo_lead.cao_vacinas_ok);
    inputs.resumo_lead.cao_antipulgas_ok = normSaude(inputs.resumo_lead.cao_antipulgas_ok);
    inputs.resumo_lead.cao_vermifugacao_ok = normSaude(inputs.resumo_lead.cao_vermifugacao_ok);

    inputs.resumo_interno_repasse.cao_vacinas_ok = normSaude(inputs.resumo_interno_repasse.cao_vacinas_ok);
    inputs.resumo_interno_repasse.cao_antipulgas_ok = normSaude(inputs.resumo_interno_repasse.cao_antipulgas_ok);

    if (inputs.resumo_interno_repasse.cao_vermifugacao_ok !== undefined) {
      inputs.resumo_interno_repasse.cao_vermifugacao_ok = normSaude(inputs.resumo_interno_repasse.cao_vermifugacao_ok);
    }

    return inputs;
  })()
}}

