parameters.jsCode:
/*
  ============================================================
  NODE: PREPARA TRILHA COMPROVANTE
  ============================================================

  Objetivo:
  Este node prepara uma resposta curta quando o lead envia um anexo
  em contexto real de pagamento.

  Importante:
  - Este node NÃO valida pagamento.
  - Este node NÃO confirma comprovante sozinho.
  - Este node apenas pergunta se o arquivo enviado é o comprovante
    da taxa de avaliação.

  Entrada esperada:
  - O Router já decidiu que existe contexto de pagamento.
  - A mensagem atual possui anexo.
  - Ainda não há comprovante confirmado.

  Saída:
  - Mensagem para Chatwoot
  - inputs atualizados
  - resposta para o subworkflow de memória/histórico
*/

const current = items[0]?.json || {};

// ============================================================
// HELPERS
// ============================================================

function cleanText(value) {
  return String(value ?? '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;

  const v = cleanText(value).toLowerCase();

  if (['true', '1', 'sim', 'yes', 's'].includes(v)) return true;
  if (['false', '0', 'nao', 'não', 'no', 'n', ''].includes(v)) return false;

  return Boolean(value);
}

function inferTipoComprovante(message) {
  const modality = cleanText(message?.message_modality).toLowerCase();
  const hasAttachment = toBool(message?.has_attachment);

  if (!hasAttachment) return 'nao_informado';

  if (modality.startsWith('image_')) return 'imagem';

  if (modality.startsWith('document_')) return 'pdf';

  return 'nao_informado';
}

function appendObservationOnce(currentObs, newObs) {
  const currentClean = cleanText(currentObs);
  const newClean = cleanText(newObs);

  if (!newClean) return currentClean;
  if (!currentClean) return newClean;

  if (currentClean.toLowerCase().includes(newClean.toLowerCase())) {
    return currentClean;
  }

  return `${currentClean} ${newClean}`.trim();
}

// ============================================================
// IDENTIFICADORES PRINCIPAIS
// ============================================================

const phone =
  current.lead?.phone ||
  current.inputs?.resumo_lead?.tutor_telefone ||
  '';

const accountId = current.chatwoot?.account_id ?? null;
const contactId = current.chatwoot?.contact_id ?? null;
const conversationId = current.chatwoot?.conversation_id ?? null;
const messageId = current.chatwoot?.message_id ?? null;
const chatHistoryUuid = current.chatwoot?.chat_history_uuid ?? null;

// ============================================================
// MONTA INPUTS DA TRILHA
// ============================================================

const tipoComprovante = inferTipoComprovante(current.message);

const referenciaArquivo =
  cleanText(current.message?.data_url) ||
  cleanText(current.message?.source_id) ||
  '';

const nextInputs = {
  ...(current.inputs || {})
};

if (!nextInputs.resumo_lead || typeof nextInputs.resumo_lead !== 'object') {
  nextInputs.resumo_lead = {};
}

/*
  Estado correto da trilha:
  O arquivo foi recebido em contexto de pagamento,
  mas ainda não está confirmado como comprovante.
*/

nextInputs.status_lead = 'AGUARDANDO_PAGAMENTO';
nextInputs.ultima_intencao = 'RECEBEU_PIX';
nextInputs.evento_sistema = 'ANEXO_RECEBIDO';

nextInputs.apto_para_avaliacao = nextInputs.apto_para_avaliacao || 'pendente';
nextInputs.status_pagamento = 'aguardando_comprovante';

nextInputs.comprovante_recebido = false;
nextInputs.tipo_comprovante = tipoComprovante;
nextInputs.arquivo_comprovante_referencia = referenciaArquivo;

nextInputs.pre_reserva_criada = false;
nextInputs.data_hora_pre_reserva = '';

nextInputs.deve_repassar_humano = false;
nextInputs.deve_enviar_guia = false;
nextInputs.deve_solicitar_pagamento = false;
nextInputs.deve_consultar_agenda = false;
nextInputs.deve_criar_pre_reserva = false;
nextInputs.deve_encerrar_conversa = false;

nextInputs.proxima_acao = 'Aguardar o lead confirmar se o arquivo enviado é o comprovante da taxa de avaliação de R$ 100.';

nextInputs.mensagens_resposta = [
  'Só pra confirmar, esse arquivo é o comprovante de pagamento da taxa de avaliação de R$ 100?'
];

/*
  Sincroniza resumo_lead com campos da trilha.
*/

nextInputs.resumo_lead = {
  ...(nextInputs.resumo_lead || {}),
  comprovante_recebido: false,
  tipo_comprovante: tipoComprovante,
  arquivo_comprovante_referencia: referenciaArquivo,
  pre_reserva_criada: false,
  data_hora_pre_reserva: '',
  observacoes: appendObservationOnce(
    nextInputs.resumo_lead?.observacoes,
    'Arquivo recebido em contexto de pagamento. Aguardando confirmação do lead se é o comprovante da taxa de avaliação.'
  )
};

/*
  Se existir resumo_interno_repasse, mantém sincronizado.
*/

if (nextInputs.resumo_interno_repasse && typeof nextInputs.resumo_interno_repasse === 'object') {
  nextInputs.resumo_interno_repasse = {
    ...nextInputs.resumo_interno_repasse,
    comprovante_recebido: false,
    tipo_comprovante: tipoComprovante,
    observacoes: appendObservationOnce(
      nextInputs.resumo_interno_repasse?.observacoes,
      'Arquivo em contexto de pagamento; aguardando confirmação se é comprovante.'
    )
  };
}

const cleanAnswer = nextInputs.mensagens_resposta.join('\n\n');

// ============================================================
// SAÍDA PARA SUBWORKFLOW RESPONDER + MEMÓRIA + HISTÓRICO
// ============================================================

return [
  {
    json: {
      ...current,
      inputs: nextInputs,
      message: {
        ...(current.message || {}),
        clean_answer: cleanAnswer
      },
      resposta: {
        phone,
        chat_history_uuid: chatHistoryUuid,
        account_id_chatwoot: accountId,
        contact_id_chatwoot: contactId,
        conversation_id_chatwoot: conversationId,
        message_id: messageId,
        status_lead_novo: nextInputs.status_lead,
        ultima_intencao_nova: nextInputs.ultima_intencao,
        evento_sistema_novo: nextInputs.evento_sistema,
        payload_atual_json: {
          ...current,
          inputs: nextInputs,
          message: {
            ...(current.message || {}),
            clean_answer: cleanAnswer
          }
        },
        resumo_lead_json: nextInputs.resumo_lead
      }
    }
  }
];

