/*
  ============================================================
  NODE: PREPARA ESTADO BRUNA
  ============================================================

  OBJETIVO DO NODE
  ------------------------------------------------------------
  Este node substitui os dois nodes anteriores:

  1. NORMALIZA MEMÓRIA BRUNA
  2. Histórico Atualizado

  Ele faz em um único ponto o que antes estava espalhado:

  1. Lê a memória atual salva no banco, vinda do node Select Memory.
  2. Lê a mensagem atual do lead, vinda do node Merge Prmeira Memória.
  3. Normaliza a memória para o schema oficial usado pela Bruna.
  4. Preserva todos os campos necessários para o Analista CRM:
     inputs, memory, chatwoot, message, lead, agent_name e should_reply.
  5. Garante que a mensagem atual do lead sempre vença qualquer mensagem antiga salva na memória.
  6. Garante que o estado salvo na memória vença no resumo_lead, status_lead, pagamento, pré-reserva e demais campos operacionais.
  7. Evita contaminar responsavel_humano com "Flavia" quando ainda não houve repasse, transferência ou pré-reserva.
  8. Mantém null onde null é tecnicamente correto, como ids ausentes, data_url ausente e chat_history_uuid ausente.
  9. Converte null para string vazia apenas em campos textuais que a IA precisa ler com segurança.
  10. Entrega um payload final pronto para o Analista CRM rodar sempre.

  REGRA DE OURO
  ------------------------------------------------------------
  Memória = fonte da verdade do estado.
  Mensagem atual = fonte da verdade do que o lead acabou de dizer.
  Chatwoot atual = fonte da verdade dos ids da conversa atual.

  Portanto:
  - resumo_lead vem da memória normalizada.
  - message.content vem SEMPRE da mensagem atual.
  - chatwoot.message_id vem SEMPRE da mensagem atual.
  - lead.phone vem da mensagem atual ou da memória, mas nunca pode ficar vazio.
  - memory.lead_id vem da linha da tabela bruna_memoria_leads.

  ENTRADAS ESPERADAS
  ------------------------------------------------------------
  Entrada principal do node:
  - Select Memory, ou seja, a linha atual da tabela bruna_memoria_leads.

  Referência usada dentro do node:
  - $('Merge Prmeira Memória').first().json
    Este payload contém a mensagem atual interpretada, Chatwoot, lead e dados do webhook.

  SAÍDA ESPERADA
  ------------------------------------------------------------
  Um único item JSON com:

  {
    inputs: {...},
    memory: {...},
    chatwoot: {...},
    message: {...},
    lead: {...},
    agent_name: "Bruna",
    should_reply: true,
    prepara_estado_bruna_debug: {...}
  }

  OBSERVAÇÃO IMPORTANTE
  ------------------------------------------------------------
  Este node NÃO interpreta semanticamente respostas como "macho", "sim" ou "não".
  Isso é papel do Analista CRM.
  Este node só organiza, normaliza e protege o estado.
*/

// ============================================================
// 1. LEITURA DAS FONTES
// ============================================================

// Linha vinda do Select Memory.
// Em tese, depois do Upsert Memory, sempre deve existir uma linha.
// Mesmo assim, o código trata ausência para evitar crash burro.
const row = $input.first()?.json || {};

// Payload atual do fluxo, vindo do Merge Prmeira Memória.
// Este é o payload vivo da execução atual, com a mensagem recém-chegada.
const atual = $('Merge Prmeira Memória').first().json || {};

// ============================================================
// 2. HELPERS BÁSICOS
// ============================================================

function isObj(v) {
  return v && typeof v === 'object' && !Array.isArray(v);
}

function obj(v) {
  return isObj(v) ? v : {};
}

function arr(v) {
  return Array.isArray(v) ? v : [];
}

function cleanString(v) {
  if (v === undefined || v === null) return '';

  if (typeof v === 'object') {
    try {
      return JSON.stringify(v);
    } catch (e) {
      return '';
    }
  }

  return String(v)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function text(...values) {
  for (const v of values) {
    const s = cleanString(v);

    if (
      s !== '' &&
      s !== 'null' &&
      s !== 'undefined' &&
      s !== '[object Object]'
    ) {
      return s;
    }
  }

  return '';
}

function nullableText(...values) {
  const v = text(...values);
  return v || null;
}

function bool(v) {
  if (v === true) return true;
  if (v === false) return false;
  if (v === 1 || v === '1') return true;
  if (v === 0 || v === '0') return false;

  const s = String(v ?? '').trim().toLowerCase();

  return ['true', 'sim', 'yes', 'y'].includes(s);
}

function numOrNull(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function safeEnum(value, fallback) {
  const v = text(value);
  return v || fallback;
}

function pickRaw(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null) return v;
  }

  return null;
}

function pickArray(...values) {
  for (const v of values) {
    if (Array.isArray(v) && v.length) return v;
  }

  return [];
}

// ============================================================
// 3. ABRE OBJETOS DA MEMÓRIA E DO PAYLOAD ATUAL
// ============================================================

// Dados salvos no payload_ultima_resposta_json da memória.
// Isso serve como fallback, mas nunca deve vencer a mensagem atual.
const payloadSalvo = obj(row.payload_ultima_resposta_json);

// Subobjetos salvos dentro da memória.
const payloadInputs = obj(payloadSalvo.inputs);
const payloadMessage = obj(payloadSalvo.message);
const payloadChatwoot = obj(payloadSalvo.chatwoot);
const payloadLead = obj(payloadSalvo.lead);
const payloadMemory = obj(payloadSalvo.memory);

// JSONs estruturados salvos no banco.
const resumoJson = obj(row.resumo_lead_json);
const repasseJson = obj(row.resumo_interno_repasse_json);
const dadosOrigem = obj(row.dados_origem_json);

// Subobjetos do payload atual, vindo do webhook ou do fluxo antes da memória.
const atualInputs = obj(atual.inputs);
const atualMessage = obj(atual.message);
const atualChatwoot = obj(atual.chatwoot);
const atualLead = obj(atual.lead);
const atualMemory = obj(atual.memory);

// ============================================================
// 4. NORMALIZA ESTADO BASE DA MEMÓRIA
// ============================================================

// Estado operacional salvo na tabela.
// Aqui a memória é a fonte principal.
const statusLead = safeEnum(
  row.status_lead || payloadInputs.status_lead || atualInputs.status_lead,
  'NOVO_LEAD'
);

const ultimaIntencao = text(
  row.ultima_intencao,
  payloadInputs.ultima_intencao,
  atualInputs.ultima_intencao
);

const eventoSistema = text(
  row.evento_sistema_atual,
  payloadInputs.evento_sistema,
  atualInputs.evento_sistema
);

// Só pode existir responsável humano quando houve de fato repasse,
// transferência ou pré-reserva.
// Isso evita a contaminação "Flavia" em lead normal.
function hasHumanOwner() {
  return (
    bool(row.deve_repassar_humano) ||
    bool(row.pre_reserva_criada) ||
    statusLead === 'TRANSFERIDO_FLAVIA' ||
    statusLead === 'PRE_RESERVA_CRIADA'
  );
}

const podeTerResponsavel = hasHumanOwner();

const responsavelHumano = podeTerResponsavel
  ? text(row.responsavel_humano, resumoJson.responsavel_humano, repasseJson.repassar_para, 'Flavia')
  : '';

// ============================================================
// 5. NORMALIZA IDENTIDADE DO LEAD E ORIGEM
// ============================================================

// Telefone é campo crítico. Se ficar vazio, o fluxo perde a chave da memória.
const phone = text(
  atualLead.phone,
  row.phone,
  payloadLead.phone,
  resumoJson.tutor_telefone,
  resumoJson.telefone_e164
);

if (!phone) {
  throw new Error('PREPARA ESTADO BRUNA bloqueado: phone vazio após normalizar memória e mensagem atual.');
}

const tutorNome = text(
  atualLead.sender_name,
  row.nome_tutor,
  resumoJson.tutor_nome,
  resumoJson.nome_tutor,
  payloadLead.sender_name
);

const origemDetalhada = text(
  atualLead.entry_channel,
  row.origem_detalhada,
  dadosOrigem.entry_channel,
  payloadLead.entry_channel
);

const origemLead = safeEnum(
  row.origem_lead || resumoJson.origem_lead || payloadInputs.origem_lead || atualInputs.origem_lead,
  'outro'
);

// ============================================================
// 6. NORMALIZA DADOS DO CÃO
// ============================================================

// Nome, idade e raça aceitam string vazia quando ainda não foram informados.
// Isso mantém o schema completo para o Analista CRM.
const caoNome = text(
  row.nome_cao,
  resumoJson.cao_nome,
  resumoJson.nome_cao,
  payloadInputs?.resumo_lead?.cao_nome,
  atualInputs?.resumo_lead?.cao_nome
);

const caoIdadeAnos = text(
  row.idade_cao_anos,
  resumoJson.cao_idade_anos,
  resumoJson.idade_cao_anos,
  payloadInputs?.resumo_lead?.cao_idade_anos,
  atualInputs?.resumo_lead?.cao_idade_anos
);

const caoIdadeTexto = text(
  row.idade_cao_texto,
  resumoJson.cao_idade_texto,
  resumoJson.idade_cao_texto,
  payloadInputs?.resumo_lead?.cao_idade_texto,
  atualInputs?.resumo_lead?.cao_idade_texto
);

const caoRaca = text(
  row.cao_raca,
  resumoJson.cao_raca,
  payloadInputs?.resumo_lead?.cao_raca,
  atualInputs?.resumo_lead?.cao_raca
);

// ============================================================
// 7. NORMALIZA MENSAGEM ATUAL
// ============================================================

// Regra fundamental:
// A mensagem atual do lead SEMPRE vence qualquer mensagem salva na memória.
// Esse é o ponto que evita a Bruna responder usando mensagem antiga.
const messageContent = text(
  atualMessage.content,
  atualMessage.content_raw,
  payloadMessage.content,
  payloadMessage.content_raw,
  row.mensagem_ultima_lead
);

const messageRaw = text(
  atualMessage.content_raw,
  atualMessage.content,
  messageContent
);

const messageCreatedAt = text(
  atualMessage.created_at,
  payloadMessage.created_at,
  row.data_ultima_mensagem_lead
);

// ============================================================
// 8. NORMALIZA IDS E CHATWOOT
// ============================================================

// IDs atuais do Chatwoot devem vir do payload atual.
// A memória entra só como fallback.
const accountId = numOrNull(
  pickRaw(
    atualChatwoot.account_id,
    row.account_id_chatwoot,
    payloadChatwoot.account_id,
    dadosOrigem.account_id_chatwoot
  )
);

const contactId = numOrNull(
  pickRaw(
    atualChatwoot.contact_id,
    row.contact_id_chatwoot,
    payloadChatwoot.contact_id,
    dadosOrigem.contact_id_chatwoot
  )
);

const conversationId = numOrNull(
  pickRaw(
    atualChatwoot.conversation_id,
    row.conversation_id_chatwoot,
    payloadChatwoot.conversation_id,
    dadosOrigem.conversation_id_chatwoot
  )
);

const messageId = numOrNull(
  pickRaw(
    atualChatwoot.message_id,
    payloadChatwoot.message_id
  )
);

const inboxId = numOrNull(
  pickRaw(
    atualChatwoot.inbox_id,
    payloadChatwoot.inbox_id
  )
);

const labels = pickArray(
  atualChatwoot.labels,
  payloadChatwoot.labels,
  row.etiquetas_chatwoot_json
);

// ============================================================
// 9. MONTA resumo_lead OFICIAL
// ============================================================

// Este objeto é o coração do estado que a Bruna e o Analista CRM usam.
// Campos desconhecidos ficam como "" ou placeholder oficial.
const resumoLead = {
  tutor_nome: tutorNome,
  tutor_telefone: phone,
  email_tutor: text(row.email_tutor, resumoJson.email_tutor, payloadInputs.email, atualInputs.email),

  cao_nome: caoNome,
  cao_idade_anos: caoIdadeAnos,
  cao_idade_texto: caoIdadeTexto,
  cao_raca: caoRaca,

  cao_porte: safeEnum(row.cao_porte || resumoJson.cao_porte, 'nao_definido'),
  cao_sexo: safeEnum(row.cao_sexo || resumoJson.cao_sexo, 'nao_informado'),
  cao_castrado: safeEnum(row.cao_castrado || resumoJson.cao_castrado, 'nao_informado'),
  cao_no_cio: safeEnum(row.cao_no_cio || resumoJson.cao_no_cio, 'nao_informado'),
  cao_vacinas_ok: safeEnum(row.cao_vacinas_ok || resumoJson.cao_vacinas_ok, 'nao_informado'),
  cao_antipulgas_ok: safeEnum(row.cao_antipulgas_ok || resumoJson.cao_antipulgas_ok, 'nao_informado'),
  cao_vermifugacao_ok: safeEnum(row.cao_vermifugacao_ok || resumoJson.cao_vermifugacao_ok, 'nao_informado'),
  cao_sociavel: safeEnum(row.cao_sociavel || resumoJson.cao_sociavel, 'nao_informado'),
  cao_reativo: safeEnum(row.cao_reativo || resumoJson.cao_reativo, 'nao_informado'),
  possui_relatorio_veterinario: safeEnum(row.possui_relatorio_veterinario || resumoJson.possui_relatorio_veterinario, 'nao_informado'),

  unidade_preferida: safeEnum(row.unidade_preferida || resumoJson.unidade_preferida, 'nao_definida'),
  servico_interesse: safeEnum(row.servico_interesse || resumoJson.servico_interesse, 'nao_definido'),

  periodo_desejado: text(row.periodo_desejado, resumoJson.periodo_desejado),
  data_desejada: text(row.data_desejada, resumoJson.data_desejada),
  data_checkin_desejada: text(row.data_checkin_desejada, resumoJson.data_checkin_desejada),
  data_checkout_desejada: text(row.data_checkout_desejada, resumoJson.data_checkout_desejada),

  origem_lead: origemLead,
  origem_detalhada: origemDetalhada,

  comprovante_recebido: bool(row.comprovante_recebido || resumoJson.comprovante_recebido),
  tipo_comprovante: safeEnum(row.tipo_comprovante || resumoJson.tipo_comprovante, 'nao_informado'),
  arquivo_comprovante_referencia: text(row.arquivo_comprovante_referencia, resumoJson.arquivo_comprovante_referencia),

  data_hora_avaliacao: text(row.data_hora_avaliacao, resumoJson.data_hora_avaliacao),
  data_hora_pre_reserva: text(row.data_hora_pre_reserva, resumoJson.data_hora_pre_reserva),
  pre_reserva_criada: bool(row.pre_reserva_criada || resumoJson.pre_reserva_criada),

  responsavel_humano: responsavelHumano,
  observacoes: text(resumoJson.observacoes)
};

// ============================================================
// 10. MONTA resumo_interno_repasse
// ============================================================

// Usado para nota privada e repasse humano.
// Não deve sugerir Flavia quando não existe repasse real.
const resumoInternoRepasse = {
  repassar_para: podeTerResponsavel ? text(repasseJson.repassar_para, responsavelHumano, 'Flavia') : '',
  motivo: text(row.motivo_repasse, repasseJson.motivo),

  tutor_nome: tutorNome,
  tutor_telefone: phone,

  cao_nome: resumoLead.cao_nome,
  cao_idade_anos: resumoLead.cao_idade_anos,
  cao_idade_texto: resumoLead.cao_idade_texto,
  cao_raca: resumoLead.cao_raca,
  cao_porte: resumoLead.cao_porte,
  cao_sexo: resumoLead.cao_sexo,
  cao_castrado: resumoLead.cao_castrado,
  cao_vacinas_ok: resumoLead.cao_vacinas_ok,
  cao_antipulgas_ok: resumoLead.cao_antipulgas_ok,
  cao_sociavel: resumoLead.cao_sociavel,
  cao_reativo: resumoLead.cao_reativo,

  unidade_preferida: resumoLead.unidade_preferida,
  servico_interesse: resumoLead.servico_interesse,

  data_hora_avaliacao: resumoLead.data_hora_avaliacao,
  data_hora_pre_reserva: resumoLead.data_hora_pre_reserva,

  comprovante_recebido: resumoLead.comprovante_recebido,
  tipo_comprovante: resumoLead.tipo_comprovante,
  arquivo_comprovante_referencia: resumoLead.arquivo_comprovante_referencia,

  observacoes: text(repasseJson.observacoes)
};

// ============================================================
// 11. MONTA inputs FINAL
// ============================================================

// inputs é o contrato principal para Analista CRM, Router e Bruna.
const inputs = {
  lead_id: row.id ?? payloadMemory.lead_id ?? atualMemory.lead_id ?? null,

  status_lead: statusLead,
  ultima_intencao: ultimaIntencao,
  evento_sistema: eventoSistema,

  mensagens_resposta: [],

  resumo_lead: resumoLead,

  proxima_acao: text(payloadInputs.proxima_acao, atualInputs.proxima_acao) || (statusLead === 'NOVO_LEAD' ? 'PEDIR_DADOS_CAO' : ''),

  apto_para_avaliacao: safeEnum(row.apto_para_avaliacao, 'pendente'),
  motivo_pre_reprovacao: text(row.motivo_pre_reprovacao),

  status_pagamento: safeEnum(row.status_pagamento, 'nao_solicitado'),
  valor_avaliacao: text(row.valor_avaliacao) || '100.00',

  comprovante_recebido: resumoLead.comprovante_recebido,
  tipo_comprovante: resumoLead.tipo_comprovante,
  arquivo_comprovante_referencia: resumoLead.arquivo_comprovante_referencia,

  pre_reserva_criada: resumoLead.pre_reserva_criada,
  data_hora_avaliacao: resumoLead.data_hora_avaliacao,
  data_hora_pre_reserva: resumoLead.data_hora_pre_reserva,

  deve_repassar_humano: bool(row.deve_repassar_humano),
  motivo_repasse: text(row.motivo_repasse),
  deve_enviar_guia: bool(row.guia_enviado),

  // Estas flags operacionais começam falsas neste momento.
  // Quem deve ligar pagamento, agenda, repasse ou encerramento depois é o Analista CRM, Router ou Bruna.
  deve_solicitar_pagamento: false,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: statusLead.startsWith('ENCERRADO'),

  mensagem_ultima_lead: text(row.mensagem_ultima_lead),
  mensagem_ultima_bruna: text(row.mensagem_ultima_bruna),

  last_processed_message_id: numOrNull(row.last_processed_message_id),
  last_processed_message_id_candidate: messageId,

  contador_followup: numOrNull(row.contador_followup) || 0,
  tipo_ultimo_followup: text(row.tipo_ultimo_followup),
  ultimo_followup_em: text(row.ultimo_followup_em),

  resumo_interno_repasse: resumoInternoRepasse,

  email: text(row.email_tutor, atualInputs.email, payloadInputs.email),

  supported_input: atualInputs.supported_input !== undefined
    ? Boolean(atualInputs.supported_input)
    : (
        payloadInputs.supported_input !== undefined
          ? Boolean(payloadInputs.supported_input)
          : true
      ),

  interpreted_message: text(atualInputs.interpreted_message, payloadInputs.interpreted_message, 'text_message'),
  interpreted_modality: text(atualInputs.interpreted_modality, atualMessage.message_modality, payloadInputs.interpreted_modality, payloadMessage.message_modality, 'text_only'),
  interpreted_status: text(atualInputs.interpreted_status, payloadInputs.interpreted_status, 'ok'),

  versao_regras_negocio: text(row.versao_regras_negocio, 'v1'),
  versao_contrato_payload: text(row.versao_contrato_payload, 'v1')
};

// ============================================================
// 12. MONTA memory FINAL
// ============================================================

// memory guarda estado anterior para auditoria, comparação e persistência.
const memory = {
  lead_id: row.id ?? atualMemory.lead_id ?? null,

  status_lead_anterior: statusLead,
  ultima_intencao_anterior: ultimaIntencao || null,
  evento_sistema_anterior: eventoSistema || null,

  chat_history_uuid: row.chat_history_uuid || payloadChatwoot.chat_history_uuid || atualChatwoot.chat_history_uuid || null,

  contador_followup: inputs.contador_followup,
  tipo_ultimo_followup: inputs.tipo_ultimo_followup,
  ultimo_followup_em: inputs.ultimo_followup_em,

  last_processed_message_id: inputs.last_processed_message_id
};

// ============================================================
// 13. MONTA chatwoot FINAL
// ============================================================

// Chatwoot atual vence porque representa a conversa e mensagem que dispararam esta execução.
const chatwoot = {
  chat_history_uuid: row.chat_history_uuid || atualChatwoot.chat_history_uuid || payloadChatwoot.chat_history_uuid || null,

  labels,

  system_event: text(atualChatwoot.system_event, payloadChatwoot.system_event, 'MESSAGE_RECEIVED'),

  account_id: accountId,
  contact_id: contactId,
  conversation_id: conversationId,

  // message_id precisa ser o ID da mensagem atual do lead.
  message_id: messageId,

  event: text(atualChatwoot.event, payloadChatwoot.event, 'message_created'),
  inbox_id: inboxId
};

// ============================================================
// 14. MONTA message FINAL
// ============================================================

// message.content é a mensagem atual do lead.
// Nunca deixar payload salvo na memória vencer aqui.
const message = {
  message_modality: text(atualMessage.message_modality, inputs.interpreted_modality, payloadMessage.message_modality, 'text_only'),

  has_text: atualMessage.has_text !== undefined
    ? Boolean(atualMessage.has_text)
    : (
        payloadMessage.has_text !== undefined
          ? Boolean(payloadMessage.has_text)
          : Boolean(messageContent)
      ),

  has_attachment: atualMessage.has_attachment !== undefined
    ? Boolean(atualMessage.has_attachment)
    : (
        payloadMessage.has_attachment !== undefined
          ? Boolean(payloadMessage.has_attachment)
          : Boolean(atualMessage.data_url || payloadMessage.data_url)
      ),

  private: atualMessage.private !== undefined
    ? Boolean(atualMessage.private)
    : (
        payloadMessage.private !== undefined
          ? Boolean(payloadMessage.private)
          : false
      ),

  type: text(atualMessage.type, payloadMessage.type, 'incoming'),

  content: messageContent,
  content_raw: messageRaw,

  data_url: pickRaw(atualMessage.data_url, payloadMessage.data_url, null),
  source_id: pickRaw(atualMessage.source_id, payloadMessage.source_id, null),
  created_at: messageCreatedAt
};

// ============================================================
// 15. MONTA lead FINAL
// ============================================================

// lead atual vence para nome, telefone, origem e UTMs.
const lead = {
  sender_name: text(atualLead.sender_name, payloadLead.sender_name, tutorNome),
  phone,
  entry_channel: origemDetalhada,
  utms: isObj(atualLead.utms) ? atualLead.utms : (isObj(payloadLead.utms) ? payloadLead.utms : {}),
  sender_type: text(atualLead.sender_type, payloadLead.sender_type, 'contact')
};

// ============================================================
// 16. SAÍDA FINAL
// ============================================================

return [
  {
    json: {
      inputs,
      memory,
      chatwoot,
      message,
      lead,

      agent_name: text(atual.agent_name, payloadSalvo.agent_name, 'Bruna'),

      should_reply: atual.should_reply !== undefined
        ? Boolean(atual.should_reply)
        : (
            payloadSalvo.should_reply !== undefined
              ? Boolean(payloadSalvo.should_reply)
              : true
          ),

      // Debug visível para validar rapidamente se o node fez o que deveria.
      prepara_estado_bruna_debug: {
        ok: true,
        node: 'PREPARA ESTADO BRUNA',
        substitui_nodes: [
          'NORMALIZA MEMÓRIA BRUNA',
          'Histórico Atualizado'
        ],

        regra_estado: 'memoria_normalizada_vence_em_inputs_e_resumo_lead',
        regra_mensagem: 'mensagem_atual_vence_em_message_content_e_chatwoot_message_id',

        lead_id: memory.lead_id,
        phone,
        status_lead: inputs.status_lead,
        ultima_intencao: inputs.ultima_intencao,
        evento_sistema: inputs.evento_sistema,

        message_id_atual: chatwoot.message_id,
        conversation_id_atual: chatwoot.conversation_id,
        account_id_atual: chatwoot.account_id,
        contact_id_atual: chatwoot.contact_id,

        message_content_final: message.content,

        responsavel_humano_preservado: Boolean(responsavelHumano),
        payload_salvo_tinha_message: Object.keys(payloadMessage).length > 0,
        payload_atual_tinha_message: Object.keys(atualMessage).length > 0
      }
    }
  }
];

/*
  ============================================================
  NODE: CALCULA QTD MSG CRM
  ============================================================

  OBJETIVO DO NODE
  ------------------------------------------------------------
  Este node calcula, ANTES de chamar o subworkflow do Analista CRM,
  quantas mensagens do Chatwoot devem ser buscadas e quantas mensagens
  anteriores ao bloco atual do lead devem ser enviadas como contexto.

  Ele existe para manter o subworkflow mais simples e reutilizável.

  O subworkflow do Analista CRM NÃO deve decidir essas quantidades.
  Ele só deve receber:
  - account_id
  - conversation_id
  - processar_IA
  - qtd_messages
  - contexto_anterior_limit
  - nome_agente
  - payload_base

  REGRA DE OURO
  ------------------------------------------------------------
  O fluxo principal conhece melhor o estado operacional do lead.
  Portanto, ele decide o tamanho da busca.

  O subworkflow apenas executa:
  1. busca mensagens no Chatwoot
  2. prepara contexto
  3. roda ou não a IA
  4. devolve o estado analisado

  ESTRATÉGIA DE CÁLCULO
  ------------------------------------------------------------
  qtd_messages:
  - define quantas mensagens serão buscadas do Chatwoot
  - precisa ser alta o suficiente para capturar blocos grandes do lead
  - exemplo extremo: lead manda 50 mensagens seguidas
  - por isso, o padrão seguro é 100

  contexto_anterior_limit:
  - define quantas mensagens anteriores ao bloco atual do lead serão usadas
  - o bloco atual do lead entra completo
  - esse número controla apenas o contexto antes do bloco
  - padrão recomendado: 15

  EXEMPLO
  ------------------------------------------------------------
  Se o lead mandou:
  - 50 mensagens seguidas agora
  - e antes disso existiam mensagens da Bruna

  O subworkflow deve conseguir montar:
  - bloco atual do lead com as 50 mensagens
  - mais 15 mensagens anteriores para contexto

  Por isso qtd_messages não pode ser baixo demais.

  SAÍDA DO NODE
  ------------------------------------------------------------
  Este node devolve o payload original inteiro, acrescentando no topo:

  {
    account_id,
    conversation_id,
    processar_IA,
    qtd_messages,
    contexto_anterior_limit,
    nome_agente,
    payload_base
  }

  payload_base é o próprio estado completo vindo do PREPARA ESTADO BRUNA.
*/

// ============================================================
// 1. LÊ O PAYLOAD BASE VINDO DO PREPARA ESTADO BRUNA
// ============================================================

const current = $input.first()?.json || {};

// ============================================================
// 2. HELPERS
// ============================================================

function clean(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function norm(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function numOrNull(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function bool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;

  const v = norm(value);
  return ['true', 'sim', 'yes', 'y'].includes(v);
}

function clamp(value, min, max) {
  const n = Number(value);

  if (!Number.isFinite(n)) return min;
  if (n < min) return min;
  if (n > max) return max;

  return n;
}

// ============================================================
// 3. EXTRAI CAMPOS IMPORTANTES DO ESTADO ATUAL
// ============================================================

const inputs = current.inputs || {};
const resumo = inputs.resumo_lead || {};
const memory = current.memory || {};
const chatwoot = current.chatwoot || {};
const message = current.message || {};
const lead = current.lead || {};

const statusLead = clean(inputs.status_lead);
const ultimaIntencao = clean(inputs.ultima_intencao);
const eventoSistema = clean(inputs.evento_sistema);

const messageContent = clean(message.content);
const messageModality = clean(message.message_modality);
const hasAttachment = bool(message.has_attachment);

const chatHistoryUuid = clean(memory.chat_history_uuid || chatwoot.chat_history_uuid);

const accountId = numOrNull(chatwoot.account_id);
const conversationId = numOrNull(chatwoot.conversation_id);
const messageId = numOrNull(chatwoot.message_id);

const nomeAgente = clean(current.agent_name || 'Bruna');

// ============================================================
// 4. VALIDA CAMPOS OBRIGATÓRIOS PARA O SUBWORKFLOW
// ============================================================

if (!accountId) {
  throw new Error('CALCULA QTD MSG CRM bloqueado: account_id vazio ou inválido.');
}

if (!conversationId) {
  throw new Error('CALCULA QTD MSG CRM bloqueado: conversation_id vazio ou inválido.');
}

if (!messageId) {
  throw new Error('CALCULA QTD MSG CRM bloqueado: chatwoot.message_id vazio ou inválido.');
}

if (!clean(lead.phone || resumo.tutor_telefone)) {
  throw new Error('CALCULA QTD MSG CRM bloqueado: telefone do lead vazio.');
}

// ============================================================
// 5. CLASSIFICA COMPLEXIDADE DO TURNO
// ============================================================

// Primeiro atendimento ou memória ainda sem chat_history_uuid.
// Normalmente precisa de mais contexto.
const primeiraInteracaoOuMemoriaNova = !chatHistoryUuid;

// Mensagem com anexo costuma envolver comprovante, imagem, documento ou áudio.
// Precisa de mais contexto para evitar decisão errada.
const turnoComAnexo = hasAttachment || /image|document|audio|video|attachment/.test(norm(messageModality));

// Estados sensíveis exigem mais mensagens para o Analista entender a trilha.
const statusSensivel = [
  'AGUARDANDO_PAGAMENTO',
  'COMPROVANTE_RECEBIDO',
  'AGUARDANDO_ESCOLHA_HORARIO',
  'PRE_RESERVA_CRIADA',
  'TRANSFERIDO_FLAVIA',
  'PRE_REPROVADO'
].includes(statusLead);

// Eventos sensíveis exigem mais contexto.
const eventoSensivel = [
  'PIX_SOLICITADO',
  'ANEXO_RECEBIDO',
  'COMPROVANTE_IDENTIFICADO',
  'AGENDA_CONSULTADA',
  'HORARIOS_ENVIADOS',
  'PRE_RESERVA_CRIADA',
  'REPASSE_FLAVIA',
  'CONVERSA_ENCERRADA'
].includes(eventoSistema);

// Intenções que costumam causar mudança de rota.
const intencaoSensivel = [
  'PEDIU_VALOR',
  'OBJECAO_PRECO',
  'ACEITOU_AVALIACAO',
  'ENVIOU_COMPROVANTE',
  'ESCOLHEU_HORARIO',
  'PEDIU_HUMANO',
  'MACHO_NAO_CASTRADO',
  'RACA_POTENCIAL_DANO'
].includes(ultimaIntencao);

// Mensagem atual longa ou em várias linhas.
// Pode indicar que o lead mandou várias informações juntas.
const linhasMensagemAtual = messageContent
  .split('\n')
  .map(x => x.trim())
  .filter(Boolean).length;

const mensagemAtualLonga =
  messageContent.length >= 350 ||
  linhasMensagemAtual >= 4;

// Perguntas de preço, localização, visita, hotel e processo costumam precisar de contexto.
const mensagemPedeInfoOuPreco = /quanto|valor|preco|preço|diaria|diária|hotel|hospedagem|creche|day use|localiza|endereco|endereço|visita|como funciona|avalia[cç][aã]o|adapta[cç][aã]o/i.test(messageContent);

// Possível bloco com múltiplas mensagens.
// Aqui ainda não sabemos quantas mensagens consecutivas o lead mandou,
// porque isso será descoberto dentro do subworkflow.
// Então usamos sinais indiretos para buscar uma janela maior.
const possivelBlocoGrande =
  mensagemAtualLonga ||
  mensagemPedeInfoOuPreco ||
  turnoComAnexo;

// ============================================================
// 6. CALCULA qtd_messages
// ============================================================

/*
  Regras práticas:

  80 mensagens:
  - caso normal
  - suficiente para capturar bloco atual + algum contexto

  100 mensagens:
  - padrão seguro
  - bom para quase todos os atendimentos

  120 mensagens:
  - primeira interação, anexo, pagamento, agenda, pré-reserva ou conflito

  150 mensagens:
  - casos muito sensíveis, onde não dá para perder contexto
*/

let qtdMessages = 100;

const motivosQtd = [];

if (primeiraInteracaoOuMemoriaNova) {
  qtdMessages = Math.max(qtdMessages, 120);
  motivosQtd.push('memoria_nova_ou_sem_chat_history_uuid');
}

if (turnoComAnexo) {
  qtdMessages = Math.max(qtdMessages, 120);
  motivosQtd.push('turno_com_anexo');
}

if (statusSensivel) {
  qtdMessages = Math.max(qtdMessages, 120);
  motivosQtd.push('status_sensivel');
}

if (eventoSensivel) {
  qtdMessages = Math.max(qtdMessages, 120);
  motivosQtd.push('evento_sensivel');
}

if (intencaoSensivel) {
  qtdMessages = Math.max(qtdMessages, 110);
  motivosQtd.push('intencao_sensivel');
}

if (possivelBlocoGrande) {
  qtdMessages = Math.max(qtdMessages, 120);
  motivosQtd.push('possivel_bloco_grande');
}

// Se já está em etapa final ou humana, aumenta para reduzir risco operacional.
if (
  statusLead === 'TRANSFERIDO_FLAVIA' ||
  statusLead === 'PRE_RESERVA_CRIADA' ||
  eventoSistema === 'REPASSE_FLAVIA' ||
  eventoSistema === 'PRE_RESERVA_CRIADA'
) {
  qtdMessages = Math.max(qtdMessages, 150);
  motivosQtd.push('etapa_final_ou_humana');
}

// Proteção final para não deixar exagerar nem ficar baixo demais.
qtdMessages = clamp(qtdMessages, 80, 150);

// ============================================================
// 7. CALCULA contexto_anterior_limit
// ============================================================

/*
  contexto_anterior_limit não é o total de mensagens para buscar.
  Ele é o total de mensagens ANTES do bloco atual do lead que serão
  enviadas para a IA como contexto.

  O bloco atual do lead entra completo.

  Padrão:
  - 15 mensagens anteriores

  Casos mais sensíveis:
  - 20 ou 25 mensagens anteriores
*/

let contextoAnteriorLimit = 15;

const motivosContexto = [];

if (primeiraInteracaoOuMemoriaNova) {
  contextoAnteriorLimit = Math.max(contextoAnteriorLimit, 20);
  motivosContexto.push('memoria_nova_ou_primeira_interacao');
}

if (turnoComAnexo || statusSensivel || eventoSensivel) {
  contextoAnteriorLimit = Math.max(contextoAnteriorLimit, 25);
  motivosContexto.push('contexto_operacional_sensivel');
}

if (possivelBlocoGrande) {
  contextoAnteriorLimit = Math.max(contextoAnteriorLimit, 20);
  motivosContexto.push('possivel_bloco_grande');
}

// Proteção final.
contextoAnteriorLimit = clamp(contextoAnteriorLimit, 10, 30);

// ============================================================
// 8. LIMPA PAYLOAD_BASE ANTES DE ENVIAR AO SUBWORKFLOW
// ============================================================

/*
  O payload_base será enviado inteiro para o subworkflow do Analista CRM.

  Por isso, removemos campos de debug temporário gerados em nodes anteriores.
  Esses campos são úteis no fluxo principal, mas não devem ser enviados como
  estado-base para o Analista CRM, porque:

  1. duplicam informação
  2. aumentam o payload sem necessidade
  3. podem confundir auditoria
  4. podem voltar no retorno do subworkflow e crescer em cascata

  Regra:
  - remove apenas campos técnicos de debug
  - preserva inputs, memory, chatwoot, message, lead e demais campos operacionais
*/

function removeDebugFields(value) {
  if (Array.isArray(value)) {
    return value.map(removeDebugFields);
  }

  if (value && typeof value === 'object') {
    const output = {};

    for (const [key, val] of Object.entries(value)) {
      const isDebugField =
        key.endsWith('_debug') ||
        key === 'prepara_estado_bruna_debug' ||
        key === 'nullable_normalizer_debug' ||
        key === 'historico_atualizado_debug' ||
        key === 'calcula_qtd_msg_crm_debug';

      if (isDebugField) continue;

      output[key] = removeDebugFields(val);
    }

    return output;
  }

  return value;
}

const payloadBaseLimpo = removeDebugFields(current);

// ============================================================
// 9. MONTA SAÍDA PARA O EXECUTE WORKFLOW
// ============================================================

return [
  {
    json: {

      account_id: accountId,
      conversation_id: conversationId,
      processar_IA: true,
      qtd_messages: qtdMessages,
      contexto_anterior_limit: contextoAnteriorLimit,
      nome_agente: nomeAgente,

      ...current,
      // Payload completo, mas sem campos de debug temporários.
      payload_base: payloadBaseLimpo,

      calcula_qtd_msg_crm_debug: {
        ok: true,
        node: 'CALCULA QTD MSG CRM',

        account_id: accountId,
        conversation_id: conversationId,
        message_id: messageId,

        status_lead: statusLead,
        ultima_intencao: ultimaIntencao,
        evento_sistema: eventoSistema,

        message_modality: messageModality,
        has_attachment: turnoComAnexo,
        message_length: messageContent.length,
        message_lines: linhasMensagemAtual,

        primeira_interacao_ou_memoria_nova: primeiraInteracaoOuMemoriaNova,
        status_sensivel: statusSensivel,
        evento_sensivel: eventoSensivel,
        intencao_sensivel: intencaoSensivel,
        possivel_bloco_grande: possivelBlocoGrande,

        qtd_messages: qtdMessages,
        contexto_anterior_limit: contextoAnteriorLimit,

        motivos_qtd_messages: motivosQtd,
        motivos_contexto_anterior: motivosContexto
      }
    }
  }
];

/*
  ============================================================
  NODE: SANITIZA PAYLOAD FINAL
  ============================================================

  Objetivo:
  Este node roda depois de:
  1. Analista de CRM
  2. VALIDA SAIDA CRM
  3. APLICA CRM NO PAYLOAD

  Ele prepara o payload final antes do Router/Bruna.

  O que ele faz:
  - Remove caracteres invisíveis.
  - Remove "[object Object]" acidental.
  - Preserva quebras de linha em campos importantes.
  - Protege URLs, source_id e tokens.
  - Remove arrays pesados que não precisam ir para frente.
  - Não reconsolida mensagens.
  - Não recalcula should_reply.
  - Não altera status, intenção, evento, sexo, castração ou regra de negócio.

  Regra de ouro:
  Este node limpa payload.
  Ele não pensa.
  Ele não decide.
  Ele não tenta corrigir conversa.
*/

const item = $input.first().json || {};

// ============================================================
// CONFIGURAÇÕES
// ============================================================

/*
  Campos que não devem ser alterados.
  Importante para não quebrar URLs, IDs externos, tokens e flags técnicas.
*/

const PROTECTED_KEYS = new Set([
  'data_url',
  'source_id',
  'pubsub_token',
  'hmac_verified',
  'display_url',
  'thumb_url',
  'url'
]);

/*
  Campos que devem preservar quebras de linha.
  Isso é essencial para histórico, mensagens agrupadas e contexto do CRM.
*/

const PRESERVE_NEWLINES_KEYS = new Set([
  'content',
  'content_raw',
  'content_last_message',
  'history_for_crm',
  'current_lead_block_text',
  'last_bruna_message_before_current_block',
  'last_human_message_before_current_block',
  'last_human_note_before_current_block',
  'proxima_acao',
  'observacoes',
  'motivo_repasse',
  'ultima_mensagem_relevante_lead',
  'ultima_mensagem_relevante_bruna',
  'estado_reconstruido_com_base_em',
  'descricao_conflito'
]);

/*
  Campos pesados ou temporários que não precisam ir para a Bruna.
  Eles foram úteis para análise, mas viram peso morto depois do CRM.
*/

const DROP_KEYS = new Set([
  'chatwoot_messages',
  'chatwoot_messages_all',
  'messages_for_crm',
  'current_lead_block_messages',
  'contexto_anterior_messages',
  'raw_block',
  'attachments',
  'payload_base',
  'prepara_contexto_crm_debug',
  'normalizador_bloco'
]);

// ============================================================
// HELPERS
// ============================================================

function cleanBaseString(value) {
  return String(value ?? '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function cleanPreserveNewlines(value) {
  return cleanBaseString(value)
    .split('\n')
    .map(line => line.replace(/[ \t]+/g, ' ').trim())
    .filter(Boolean)
    .join('\n')
    .trim();
}

function cleanInline(value) {
  return cleanBaseString(value)
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitizeValue(value, key = '') {
  /*
    Remove campos pesados.
  */

  if (DROP_KEYS.has(key)) {
    return undefined;
  }

  /*
    Protege campos sensíveis.
  */

  if (PROTECTED_KEYS.has(key)) {
    return value;
  }

  /*
    Sanitiza strings.
  */

  if (typeof value === 'string') {
    if (PRESERVE_NEWLINES_KEYS.has(key)) {
      return cleanPreserveNewlines(value);
    }

    return cleanInline(value);
  }

  /*
    Sanitiza arrays.
  */

  if (Array.isArray(value)) {
    const sanitizedArray = value
      .map(entry => sanitizeValue(entry, key))
      .filter(entry => entry !== undefined);

    return sanitizedArray;
  }

  /*
    Sanitiza objetos.
  */

  if (value && typeof value === 'object') {
    const output = {};

    for (const [childKey, childValue] of Object.entries(value)) {
      const sanitized = sanitizeValue(childValue, childKey);

      if (sanitized !== undefined) {
        output[childKey] = sanitized;
      }
    }

    return output;
  }

  return value;
}

// ============================================================
// SANITIZA PAYLOAD
// ============================================================

const sanitized = sanitizeValue(item) || {};

// ============================================================
// GARANTIAS MÍNIMAS SEM REPROCESSAR MENSAGEM
// ============================================================

/*
  Não recalculamos should_reply.
  Apenas garantimos boolean quando existir.
*/

if ('should_reply' in sanitized) {
  sanitized.should_reply = sanitized.should_reply !== false;
}

/*
  Preserva modalidade já decidida antes.
  Este node não deve recalcular image_only, text_only, etc.
*/

if (sanitized.message && typeof sanitized.message === 'object') {
  sanitized.message.message_modality = cleanInline(sanitized.message.message_modality || '');
  sanitized.message.has_text = Boolean(sanitized.message.has_text);
  sanitized.message.has_attachment = Boolean(sanitized.message.has_attachment);
}

if (sanitized.memory && sanitized.memory.evento_sistema_anterior == null) {
  sanitized.memory.evento_sistema_anterior = '';
}

/*
  Debug leve.
*/

// sanitized.sanitiza_payload_final_debug = {
//   ok: true,
//   node: 'SANITIZA PAYLOAD FINAL',
//   status_lead: sanitized.inputs?.status_lead || '',
//   ultima_intencao: sanitized.inputs?.ultima_intencao || '',
//   evento_sistema: sanitized.inputs?.evento_sistema || '',
//   should_reply: sanitized.should_reply,
//   message_modality: sanitized.message?.message_modality || '',
//   has_text: sanitized.message?.has_text ?? null,
//   has_attachment: sanitized.message?.has_attachment ?? null,
//   has_history_for_crm: Boolean(sanitized.message?.history_for_crm)
// };

return [
  {
    json: sanitized
  }
];

/*
  ============================================================
  NODE: 02.1 PREPARAR ROUTER OPERACIONAL
  ============================================================

  Objetivo:
  Este node roda depois do SANITIZA PAYLOAD FINAL.

  Ele NÃO interpreta conversa.
  Ele NÃO decide preço, intenção, pesquisa futura, serviço ou objeção.
  Ele NÃO cria guardrails semânticos para a Bruna.
  Ele NÃO reescreve status do lead, salvo no caso objetivo de repasse humano.

  Responsabilidade:
  Definir apenas a rota operacional:

  1. IGNORAR
  2. REPASSE_HUMANO
  3. TRILHA_COMPROVANTE
  4. PROCESSAR_BRUNA

  Regra de ouro:
  Analista CRM decide estado.
  Router decide caminho operacional.
*/

// ============================================================
// CONFIGURAÇÕES DE PRODUÇÃO
// ============================================================

/*
  Durante teste manual, você pode deixar false.
  Em produção, volte para true.
*/

const BLOQUEAR_HUMANO_ASSUMIDO = true;

/*
  Durante teste manual, você pode deixar false.
  Em produção, volte para true se last_processed_message_id for gravado
  depois do envio ou depois da decisão final de não responder.
*/

const BLOQUEAR_MENSAGEM_JA_PROCESSADA = true;

// ============================================================
// PAYLOAD BASE
// ============================================================

const item = $json || {};

const inputs = item.inputs && typeof item.inputs === 'object' ? item.inputs : {};
const memory = item.memory && typeof item.memory === 'object' ? item.memory : {};
const message = item.message && typeof item.message === 'object' ? item.message : {};
const chatwoot = item.chatwoot && typeof item.chatwoot === 'object' ? item.chatwoot : {};
const lead = item.lead && typeof item.lead === 'object' ? item.lead : {};

// ============================================================
// HELPERS
// ============================================================

function cleanText(value) {
  return String(value ?? '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .trim();
}

function norm(value) {
  return cleanText(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;

  const v = norm(value);

  if (['true', '1', 'sim', 'yes', 's'].includes(v)) return true;
  if (['false', '0', 'nao', 'não', 'no', 'n', ''].includes(v)) return false;

  return Boolean(value);
}

function numberOrZero(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : 0;
}

function labelList(value) {
  if (!Array.isArray(value)) return [];

  return value
    .map(label => norm(label))
    .filter(Boolean);
}

function hasLabel(labels, candidates) {
  return candidates.some(candidate => labels.includes(norm(candidate)));
}

// ============================================================
// CAMPOS NORMALIZADOS
// ============================================================

const labels = labelList(chatwoot.labels);

const statusLead = cleanText(inputs.status_lead || '');
const ultimaIntencao = cleanText(inputs.ultima_intencao || '');
const eventoSistema = cleanText(inputs.evento_sistema || '');
const statusPagamento = cleanText(inputs.status_pagamento || '');

const shouldReplyOriginal = item.should_reply !== false;

const mensagemPrivada = toBool(message.private);

const messageType = norm(message.type);
const chatwootEvent = norm(chatwoot.event || item.event);

const mensagemDeSaida =
  messageType === 'outgoing' ||
  messageType === 'activity' ||
  chatwootEvent === 'message_updated';

const hasAttachment = toBool(message.has_attachment);
const hasText = toBool(message.has_text);
const messageContent = cleanText(message.content || message.content_raw || '');

const mensagemVazia = !messageContent && !hasAttachment;

const mensagemDuplicada =
  toBool(item.message_is_duplicate) ||
  toBool(message.is_duplicate) ||
  toBool(inputs.message_is_duplicate);

const currentMessageId = numberOrZero(
  message.current_message_id ||
  message.last_message_id ||
  chatwoot.message_id
);

const lastProcessedMessageId = numberOrZero(
  memory.last_processed_message_id ||
  inputs.last_processed_message_id
);

const mensagemJaProcessada =
  currentMessageId > 0 &&
  lastProcessedMessageId > 0 &&
  currentMessageId <= lastProcessedMessageId;

const leadEncerrado =
  toBool(memory.encerrado) ||
  statusLead.startsWith('ENCERRADO') ||
  hasLabel(labels, ['99-lead-desqualificado']);

const humanoAssumiu =
  hasLabel(labels, [
    '01-humano-assumiu',
    'humano',
    'flavia',
    'flávia'
  ]);

const brunaAtiva =
  hasLabel(labels, [
    '01-bruna-atendimento'
  ]);

/*
  Repasse humano deve vir principalmente do Analista CRM.
  O Router não precisa mais detectar isso por regex.
*/

const crmPediuRepasseHumano =
  toBool(inputs.deve_repassar_humano) ||
  statusLead === 'TRANSFERIDO_FLAVIA' ||
  ultimaIntencao === 'PEDIU_HUMANO' ||
  eventoSistema === 'REPASSE_FLAVIA';

/*
  Comprovante:
  O Router só manda para TRILHA_COMPROVANTE quando há anexo
  e o estado operacional indica contexto real de pagamento.
*/

const comprovanteJaRecebido =
  toBool(inputs.comprovante_recebido) ||
  toBool(inputs?.resumo_lead?.comprovante_recebido) ||
  toBool(inputs?.resumo_interno_repasse?.comprovante_recebido) ||
  ['COMPROVANTE_RECEBIDO', 'AGUARDANDO_ESCOLHA_HORARIO', 'PRE_RESERVA_CRIADA'].includes(statusLead) ||
  eventoSistema === 'COMPROVANTE_IDENTIFICADO';

const contextoPagamento =
  statusLead === 'AGUARDANDO_PAGAMENTO' ||
  eventoSistema === 'PIX_SOLICITADO' ||
  ultimaIntencao === 'RECEBEU_PIX' ||
  ultimaIntencao === 'ACEITOU_AVALIACAO' ||
  statusPagamento === 'aguardando_comprovante' ||
  statusPagamento === 'pendente_comprovante';

const podeSerComprovante =
  hasAttachment &&
  contextoPagamento &&
  !comprovanteJaRecebido;

const anexoForaPagamento =
  hasAttachment &&
  !podeSerComprovante;

// ============================================================
// DECISÃO DE ROTA
// ============================================================

let rota = 'PROCESSAR_BRUNA';
let motivo = 'fluxo_padrao';

if (!shouldReplyOriginal) {
  rota = 'IGNORAR';
  motivo = 'should_reply_false';
} else if (mensagemPrivada) {
  rota = 'IGNORAR';
  motivo = 'mensagem_privada';
} else if (mensagemDeSaida) {
  rota = 'IGNORAR';
  motivo = 'mensagem_nao_incoming';
} else if (mensagemDuplicada) {
  rota = 'IGNORAR';
  motivo = 'mensagem_duplicada';
} else if (BLOQUEAR_MENSAGEM_JA_PROCESSADA && mensagemJaProcessada) {
  rota = 'IGNORAR';
  motivo = 'mensagem_ja_processada';
} else if (leadEncerrado) {
  rota = 'IGNORAR';
  motivo = 'lead_encerrado';
} else if (BLOQUEAR_HUMANO_ASSUMIDO && humanoAssumiu) {
  rota = 'IGNORAR';
  motivo = 'conversa_assumida_por_humano';
} else if (BLOQUEAR_HUMANO_ASSUMIDO && !brunaAtiva) {
  rota = 'IGNORAR';
  motivo = 'sem_label_bruna_atendimento';
} else if (crmPediuRepasseHumano) {
  rota = 'REPASSE_HUMANO';
  motivo = 'crm_solicitou_repasse_humano';
} else if (podeSerComprovante) {
  rota = 'TRILHA_COMPROVANTE';
  motivo = 'anexo_em_contexto_de_pagamento';
} else if (mensagemVazia) {
  rota = 'IGNORAR';
  motivo = 'mensagem_vazia_sem_anexo';
} else {
  rota = 'PROCESSAR_BRUNA';
  motivo = anexoForaPagamento
    ? 'anexo_fora_pagamento_processar_como_contexto'
    : 'fluxo_conversacional';
}

// ============================================================
// AJUSTE MECÂNICO PARA REPASSE HUMANO
// ============================================================

/*
  Só aqui o Router altera inputs.
  Motivo: a branch REPASSE_HUMANO precisa de flags claras.
  Não fazemos inferência por regex.
*/

const inputsAtualizados = {
  ...inputs
};

if (rota === 'REPASSE_HUMANO') {
  inputsAtualizados.status_lead = 'TRANSFERIDO_FLAVIA';
  inputsAtualizados.ultima_intencao = 'PEDIU_HUMANO';
  inputsAtualizados.evento_sistema = 'REPASSE_FLAVIA';
  inputsAtualizados.deve_repassar_humano = true;
  inputsAtualizados.motivo_repasse = inputsAtualizados.motivo_repasse || 'crm_solicitou_repasse_humano';
  inputsAtualizados.deve_solicitar_pagamento = false;
  inputsAtualizados.deve_consultar_agenda = false;
  inputsAtualizados.deve_criar_pre_reserva = false;
  inputsAtualizados.deve_encerrar_conversa = false;
}

// ============================================================
// SAÍDA
// ============================================================

const roteamento = {
  rota,
  motivo,

  status_lead: statusLead,
  ultima_intencao: ultimaIntencao,
  evento_sistema: eventoSistema,

  should_reply_original: shouldReplyOriginal,
  should_reply_final: rota !== 'IGNORAR',

  mensagem_privada: mensagemPrivada,
  mensagem_de_saida: mensagemDeSaida,
  mensagem_duplicada: mensagemDuplicada,
  mensagem_ja_processada: mensagemJaProcessada,
  mensagem_vazia: mensagemVazia,

  lead_encerrado: leadEncerrado,
  humano_assumiu: humanoAssumiu,
  bruna_ativa: brunaAtiva,

  crm_pediu_repasse_humano: crmPediuRepasseHumano,

  has_text: hasText,
  has_attachment: hasAttachment,
  pode_ser_comprovante: podeSerComprovante,
  anexo_fora_pagamento: anexoForaPagamento,
  comprovante_ja_recebido: comprovanteJaRecebido,
  contexto_pagamento: contextoPagamento,

  current_message_id: currentMessageId || null,
  last_processed_message_id: lastProcessedMessageId || null,

  usar_processar_bruna: rota === 'PROCESSAR_BRUNA',
  usar_trilha_comprovante: rota === 'TRILHA_COMPROVANTE',
  usar_trilha_repasse: rota === 'REPASSE_HUMANO',
  ignorar_evento: rota === 'IGNORAR',

  labels
};

return [
  {
    json: {
      ...item,
      inputs: inputsAtualizados,
      should_reply: rota !== 'IGNORAR',
      roteamento
    }
  }
];

