const item = $input.first().json || {};

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function clean(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeKey(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^\w\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function pick(...values) {
  for (const value of values) {
    const text = clean(value);
    if (text) return text;
  }

  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => clean(x)).filter(Boolean);
  }

  if (typeof value === 'string') {
    const text = value.trim();

    if (!text) return [];

    try {
      const parsed = JSON.parse(text);
      if (Array.isArray(parsed)) {
        return parsed.map(x => clean(x)).filter(Boolean);
      }
    } catch (e) {}

    return text
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(values) {
  return [...new Set(values.map(x => clean(x)).filter(Boolean))];
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value.map(clean).filter(Boolean).slice(0, 3);
  }

  const text = clean(value);
  return text ? [text] : [];
}

function getPath(root, path) {
  const parts = clean(path).split('.').filter(Boolean);
  let current = root;

  for (const part of parts) {
    if (current === undefined || current === null) return undefined;
    current = current[part];
  }

  return current;
}

function getConfig(config, path, fallback) {
  const value = getPath(config, path);
  return value === undefined || value === null ? fallback : value;
}

function getArrayConfig(config, path) {
  const value = getConfig(config, path, []);
  return Array.isArray(value) ? value : [];
}

function getObjectConfig(config, path) {
  const value = getConfig(config, path, {});
  return isObject(value) ? value : {};
}

function getStringConfig(config, path, fallback = '') {
  const value = getConfig(config, path, fallback);
  const text = clean(value);
  return text || fallback;
}

function escapeRegExp(value) {
  return clean(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function parsePossivelJson(value) {
  if (Array.isArray(value) || isObject(value)) return value;

  const text = clean(value);
  if (!text) return null;

  try {
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

function listaTemMaisDeUmItemPreenchido(value) {
  if (!Array.isArray(value)) return false;

  const preenchidos = value.filter(item => {
    if (isObject(item)) {
      return Object.values(item).some(v => clean(v));
    }

    return clean(item);
  });

  return preenchidos.length > 1;
}

function getPrimeiroNumeroValido(values) {
  for (const value of values) {
    const text = clean(value);

    if (!text) continue;

    const number = Number(text.replace(',', '.'));

    if (Number.isFinite(number)) {
      return number;
    }
  }

  return null;
}

function resolveLabel(labelRef, labelsConfig) {
  const ref = clean(labelRef);
  if (!ref) return '';

  return clean(labelsConfig[ref]) || ref;
}

function normalizeByConfig(value, normalizacaoConfig) {
  const text = normalizeKey(value);
  const fallback = clean(normalizacaoConfig.fallback);
  const permitidos = Array.isArray(normalizacaoConfig.permitidos)
    ? normalizacaoConfig.permitidos.map(clean)
    : [];

  const aliases = isObject(normalizacaoConfig.aliases)
    ? normalizacaoConfig.aliases
    : {};

  for (const [canonical, aliasList] of Object.entries(aliases)) {
    const aliasesNormalizados = Array.isArray(aliasList)
      ? aliasList.map(normalizeKey)
      : [];

    if (aliasesNormalizados.includes(text)) {
      return canonical;
    }
  }

  const raw = clean(value);
  if (permitidos.includes(raw)) {
    return raw;
  }

  return fallback;
}

function normalizeTipoComprovante(value, comprovanteRecebido, config) {
  const tipoConfig = getObjectConfig(config, 'normalizacao_pet.tipo_comprovante');

  if (comprovanteRecebido !== true) {
    return getStringConfig(
      config,
      'normalizacao_pet.tipo_comprovante.quando_nao_recebido',
      'nao_informado'
    );
  }

  return normalizeByConfig(value, tipoConfig);
}

function splitTextoPorConfig(value, config) {
  const text = clean(value);

  if (!text) return [];

  const separadores = getArrayConfig(config, 'multiplos_caes.separadores_texto');
  const conectores = getArrayConfig(config, 'multiplos_caes.conectores_texto');

  const tokensConfigurados = unique([
    ...separadores,
    ...conectores
  ]).map(token => token === '\\n' ? '\n' : token);

  if (!tokensConfigurados.length) {
    return [text];
  }

  const partesRegex = tokensConfigurados
    .map(token => escapeRegExp(token))
    .filter(Boolean);

  if (!partesRegex.length) {
    return [text];
  }

  const regex = new RegExp(partesRegex.join('|'), 'gi');

  return text
    .split(regex)
    .map(x => clean(x))
    .filter(Boolean);
}

function textoTemPluralConfigurado(value, config) {
  const text = normalizeKey(value);

  if (!text) return false;

  const palavrasPlural = getArrayConfig(config, 'multiplos_caes.palavras_plural');

  if (!palavrasPlural.length) {
    return false;
  }

  const tokens = text.split(/\s+/).filter(Boolean);
  const pluralSet = new Set(palavrasPlural.map(normalizeKey).filter(Boolean));

  return tokens.some(token => pluralSet.has(token));
}

function valoresPorPaths(root, paths) {
  return paths
    .map(path => getPath(root, path))
    .map(value => clean(value))
    .filter(Boolean);
}

function detectaMultiplosCaes(root, config) {
  const camposListaJson = getArrayConfig(config, 'multiplos_caes.campos_lista_json');

  for (const path of camposListaJson) {
    const value = parsePossivelJson(getPath(root, path));
    if (listaTemMaisDeUmItemPreenchido(value)) {
      return true;
    }
  }

  const camposQuantidade = getArrayConfig(config, 'multiplos_caes.campos_quantidade');
  const quantidade = getPrimeiroNumeroValido(
    camposQuantidade.map(path => getPath(root, path))
  );

  if (quantidade !== null && quantidade > 1) {
    return true;
  }

  const camposTexto = getArrayConfig(config, 'multiplos_caes.campos_texto');
  const valoresTexto = valoresPorPaths(root, camposTexto);

  const camposTextoComMaisDeUmValor = valoresTexto.some(value => {
    return splitTextoPorConfig(value, config).length > 1;
  });

  if (camposTextoComMaisDeUmValor) {
    return true;
  }

  const camposObservacao = getArrayConfig(config, 'multiplos_caes.campos_observacao');
  const valoresObservacao = valoresPorPaths(root, camposObservacao);

  const observacaoSugereMultiplos = valoresObservacao.some(value => {
    return (
      splitTextoPorConfig(value, config).length > 1 ||
      textoTemPluralConfigurado(value, config)
    );
  });

  return observacaoSugereMultiplos;
}

function montaLinhasPetNotaPrivada(root, config, multiplosCaes) {
  const labels = getObjectConfig(config, 'nota_privada_pet.labels');

  const labelPet = multiplosCaes
    ? clean(labels.pet_plural)
    : clean(labels.pet_singular);

  const labelIdade = multiplosCaes
    ? clean(labels.idade_plural)
    : clean(labels.idade_singular);

  const labelRaca = multiplosCaes
    ? clean(labels.raca_plural)
    : clean(labels.raca_singular);

  const resumoLead = root.resumo_lead || {};
  const resumoRepasse = root.resumo_interno_repasse || {};

  const perfilComportamental = pick(
    resumoRepasse.cao_perfil_comportamental,
    resumoLead.cao_perfil_comportamental
  );

  const observacoesComportamento = pick(
    resumoRepasse.cao_comportamento_observacoes,
    resumoLead.cao_comportamento_observacoes
  );

  const observacoesGerais = pick(
    resumoRepasse.observacoes,
    resumoLead.observacoes
  );

  return [
    `${labelPet}: ${pick(resumoRepasse.cao_nome, resumoLead.cao_nome) || 'não informado'}`,
    `${labelIdade}: ${pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto) || 'não informada'}`,
    `${labelRaca}: ${pick(resumoRepasse.cao_raca, resumoLead.cao_raca) || 'não informada'}`,
    `${clean(labels.porte)}: ${pick(resumoRepasse.cao_porte, resumoLead.cao_porte) || 'não informado'}`,
    `${clean(labels.sexo)}: ${pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo) || 'não informado'}`,
    `${clean(labels.castrado)}: ${pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado) || 'não informado'}`,
    `${clean(labels.servico)}: ${pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse) || 'não informado'}`,
    `${clean(labels.perfil_comportamental)}: ${perfilComportamental || 'não informado'}`,
    `${clean(labels.comportamento_observacoes)}: ${observacoesComportamento || 'sem observações de comportamento'}`,
    `${clean(labels.observacoes_gerais)}: ${observacoesGerais || 'sem observações gerais'}`,
    `${clean(labels.multiplos_caes)}: ${multiplosCaes ? 'sim' : 'não'}`
  ];
}

const inputs = { ...(item.inputs || {}) };
const message = { ...(item.message || {}) };
const chatwoot = { ...(item.chatwoot || {}) };
const lead = { ...(item.lead || {}) };
const memory = { ...(item.memory || {}) };
const config = isObject(item.config_bruna) ? item.config_bruna : {};
const opcoesOriginais = { ...(item.opcoes || {}) };

const chatwootConfig = getObjectConfig(config, 'responder_chatwoot_operacional');
const labelsConfig = isObject(config.labels) ? config.labels : {};
const notaLabels = getObjectConfig(config, 'responder_chatwoot_operacional.nota_labels');

const resumoLead = { ...(inputs.resumo_lead || {}) };
const resumoRepasse = { ...(inputs.resumo_interno_repasse || {}) };

/*
  ==================================================
  Normaliza resposta
  ==================================================
*/

const mensagensResposta = normalizeMessages(
  Array.isArray(inputs.mensagens_resposta) && inputs.mensagens_resposta.length
    ? inputs.mensagens_resposta
    : message.mensagens_resposta?.length
      ? message.mensagens_resposta
      : message.clean_answer
);

const cleanAnswer = clean(
  mensagensResposta.length
    ? mensagensResposta.join('\n\n')
    : message.clean_answer
);

inputs.mensagens_resposta = cleanAnswer
  ? cleanAnswer.split('\n\n').map(clean).filter(Boolean).slice(0, 3)
  : [];

message.clean_answer = cleanAnswer;
message.mensagens_resposta = inputs.mensagens_resposta;

/*
  ==================================================
  Normaliza resumo_lead
  ==================================================
*/

resumoLead.tutor_nome = pick(resumoLead.tutor_nome, lead.sender_name);
resumoLead.tutor_telefone = pick(resumoLead.tutor_telefone, lead.phone);

resumoLead.cao_porte = normalizeByConfig(
  resumoLead.cao_porte,
  getObjectConfig(config, 'normalizacao_pet.porte')
);

resumoLead.cao_sexo = normalizeByConfig(
  resumoLead.cao_sexo,
  getObjectConfig(config, 'normalizacao_pet.sexo')
);

resumoLead.cao_castrado = normalizeByConfig(
  resumoLead.cao_castrado,
  getObjectConfig(config, 'normalizacao_pet.castrado')
);

resumoLead.comprovante_recebido = resumoLead.comprovante_recebido === true || inputs.comprovante_recebido === true;
resumoLead.tipo_comprovante = normalizeTipoComprovante(
  pick(resumoLead.tipo_comprovante, inputs.tipo_comprovante),
  resumoLead.comprovante_recebido === true,
  config
);

resumoLead.data_hora_pre_reserva = '';
resumoLead.pre_reserva_criada = false;

/*
  ==================================================
  Normaliza resumo_interno_repasse
  ==================================================
*/

resumoRepasse.tutor_nome = pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name);
resumoRepasse.tutor_telefone = pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone);
resumoRepasse.cao_nome = pick(resumoRepasse.cao_nome, resumoLead.cao_nome);
resumoRepasse.cao_idade_anos = pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto);
resumoRepasse.cao_raca = pick(resumoRepasse.cao_raca, resumoLead.cao_raca);

resumoRepasse.cao_porte = normalizeByConfig(
  pick(resumoRepasse.cao_porte, resumoLead.cao_porte),
  getObjectConfig(config, 'normalizacao_pet.porte')
);

resumoRepasse.cao_sexo = normalizeByConfig(
  pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo),
  getObjectConfig(config, 'normalizacao_pet.sexo')
);

resumoRepasse.cao_castrado = normalizeByConfig(
  pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado),
  getObjectConfig(config, 'normalizacao_pet.castrado')
);

resumoRepasse.cao_vacinas_ok = pick(resumoRepasse.cao_vacinas_ok, resumoLead.cao_vacinas_ok);
resumoRepasse.cao_antipulgas_ok = pick(resumoRepasse.cao_antipulgas_ok, resumoLead.cao_antipulgas_ok);
resumoRepasse.cao_vermifugacao_ok = pick(resumoRepasse.cao_vermifugacao_ok, resumoLead.cao_vermifugacao_ok);

resumoRepasse.cao_perfil_comportamental = pick(
  resumoRepasse.cao_perfil_comportamental,
  resumoLead.cao_perfil_comportamental
);

resumoRepasse.cao_comportamento_observacoes = pick(
  resumoRepasse.cao_comportamento_observacoes,
  resumoLead.cao_comportamento_observacoes
);

resumoRepasse.unidade_preferida = pick(resumoRepasse.unidade_preferida, resumoLead.unidade_preferida);
resumoRepasse.servico_interesse = pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse);

resumoRepasse.comprovante_recebido = resumoLead.comprovante_recebido === true;
resumoRepasse.tipo_comprovante = normalizeTipoComprovante(
  pick(resumoRepasse.tipo_comprovante, resumoLead.tipo_comprovante, inputs.tipo_comprovante),
  resumoRepasse.comprovante_recebido === true,
  config
);

resumoRepasse.observacoes = pick(
  resumoRepasse.observacoes,
  resumoLead.observacoes
);

delete resumoLead.cao_sociavel;
delete resumoLead.cao_reativo;
delete resumoRepasse.cao_sociavel;
delete resumoRepasse.cao_reativo;

/*
  ==================================================
  Múltiplos cães
  ==================================================
*/

const root = {
  inputs,
  message,
  chatwoot,
  lead,
  memory,
  resumo_lead: resumoLead,
  resumo_interno_repasse: resumoRepasse
};

const multiplosCaes = detectaMultiplosCaes(root, config);

/*
  ==================================================
  Travas finais
  ==================================================
*/

inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.resumo_lead = resumoLead;
inputs.resumo_interno_repasse = resumoRepasse;
inputs.multiplos_caes = multiplosCaes;

/*
  Não zerar data_hora_avaliacao aqui.
*/

/*
  ==================================================
  Labels finais via config
  ==================================================
*/

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(item.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

const labelsRemover = getArrayConfig(config, 'responder_chatwoot_operacional.labels_remover')
  .map(labelRef => resolveLabel(labelRef, labelsConfig));

const removeSet = new Set(labelsRemover);
let labelsFinal = labelsAtuais.filter(label => !removeSet.has(label));

const labelsAdicionar = getArrayConfig(config, 'responder_chatwoot_operacional.labels_adicionar')
  .map(labelRef => resolveLabel(labelRef, labelsConfig));

