const eventoAtual = clean(inputs.evento_sistema);

const statusFinal = inferStatusFinal(statusAtual, ultimaIntencao, eventoAtual, config);
const eventoFinal = getStringConfig(config, 'encerramento_operacional.evento_final', 'CONVERSA_ENCERRADA');

const mensagensResposta = normalizeMessages(
