const item = $input.first().json || {};

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function clean(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeKey(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^\w\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function pick(...values) {
  for (const value of values) {
    const text = clean(value);
    if (text) return text;
  }

  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => clean(x)).filter(Boolean);
  }

  if (typeof value === 'string') {
    const text = value.trim();

    if (!text) return [];

    try {
      const parsed = JSON.parse(text);
      if (Array.isArray(parsed)) {
        return parsed.map(x => clean(x)).filter(Boolean);
      }
    } catch (e) {}

    return text
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(values) {
  return [...new Set(values.map(x => clean(x)).filter(Boolean))];
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value.map(clean).filter(Boolean).slice(0, 3);
  }

  const text = clean(value);
  return text ? [text] : [];
}

function getPath(root, path) {
  const parts = clean(path).split('.').filter(Boolean);
  let current = root;

  for (const part of parts) {
    if (current === undefined || current === null) return undefined;
    current = current[part];
  }

  return current;
}

function getConfig(config, path, fallback) {
  const value = getPath(config, path);
  return value === undefined || value === null ? fallback : value;
}

function getArrayConfig(config, path) {
  const value = getConfig(config, path, []);
  return Array.isArray(value) ? value : [];
}

function getObjectConfig(config, path) {
  const value = getConfig(config, path, {});
  return isObject(value) ? value : {};
}

function getStringConfig(config, path, fallback = '') {
  const value = getConfig(config, path, fallback);
  const text = clean(value);
  return text || fallback;
}

function escapeRegExp(value) {
  return clean(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function parsePossivelJson(value) {
  if (Array.isArray(value) || isObject(value)) return value;

  const text = clean(value);
  if (!text) return null;

  try {
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

function listaTemMaisDeUmItemPreenchido(value) {
  if (!Array.isArray(value)) return false;

  const preenchidos = value.filter(item => {
    if (isObject(item)) {
      return Object.values(item).some(v => clean(v));
    }

    return clean(item);
  });

  return preenchidos.length > 1;
}

function getPrimeiroNumeroValido(values) {
  for (const value of values) {
    const text = clean(value);

    if (!text) continue;

    const number = Number(text.replace(',', '.'));

    if (Number.isFinite(number)) {
      return number;
    }
  }

  return null;
}

function resolveLabel(labelRef, labelsConfig) {
  const ref = clean(labelRef);
  if (!ref) return '';

  return clean(labelsConfig[ref]) || ref;
}

function normalizeByConfig(value, normalizacaoConfig) {
  const text = normalizeKey(value);
  const fallback = clean(normalizacaoConfig.fallback);
  const permitidos = Array.isArray(normalizacaoConfig.permitidos)
    ? normalizacaoConfig.permitidos.map(clean)
    : [];

  const aliases = isObject(normalizacaoConfig.aliases)
    ? normalizacaoConfig.aliases
    : {};

  for (const [canonical, aliasList] of Object.entries(aliases)) {
    const aliasesNormalizados = Array.isArray(aliasList)
      ? aliasList.map(normalizeKey)
      : [];

    if (aliasesNormalizados.includes(text)) {
      return canonical;
    }
  }

  const raw = clean(value);
  if (permitidos.includes(raw)) {
    return raw;
  }

  return fallback;
}

function normalizeEnumFromConfig(value, allowed, fallback) {
  const text = clean(value);
  return allowed.includes(text) ? text : fallback;
}

function normalizeTipoComprovante(value, comprovanteRecebido, config) {
  const tipoConfig = getObjectConfig(config, 'normalizacao_pet.tipo_comprovante');

  if (comprovanteRecebido !== true) {
    return getStringConfig(config, 'normalizacao_pet.tipo_comprovante.quando_nao_recebido', 'nao_informado');
  }

  return normalizeByConfig(value, tipoConfig);
}

function inferTipoComprovante(message, inputs, resumoLead, config) {
  const tipoAtual = pick(
    inputs.tipo_comprovante,
    resumoLead.tipo_comprovante,
    message.tipo_comprovante
  );

  const normalizadoAtual = normalizeTipoComprovante(tipoAtual, true, config);
  if (normalizadoAtual !== 'nao_informado') {
    return normalizadoAtual;
  }

  const modality = normalizeKey(message.message_modality);
  const dataUrl = normalizeKey(message.data_url);

  const tipoConfig = getObjectConfig(config, 'normalizacao_pet.tipo_comprovante');

  if (modality.includes('image')) {
    return normalizeByConfig('imagem', tipoConfig);
  }

  if (modality.includes('document')) {
    return normalizeByConfig('pdf', tipoConfig);
  }

  if (dataUrl.includes('pdf')) {
    return normalizeByConfig('pdf', tipoConfig);
  }

  return normalizeTipoComprovante('', true, config);
}

function splitTextoPorConfig(value, config) {
  const text = clean(value);

  if (!text) return [];

  const separadores = getArrayConfig(config, 'multiplos_caes.separadores_texto');
  const conectores = getArrayConfig(config, 'multiplos_caes.conectores_texto');

  const tokensConfigurados = unique([
    ...separadores,
    ...conectores
  ]).map(token => token === '\\n' ? '\n' : token);

  if (!tokensConfigurados.length) {
    return [text];
  }

  const partesRegex = tokensConfigurados
    .map(token => escapeRegExp(token))
    .filter(Boolean);

  if (!partesRegex.length) {
    return [text];
  }

  const regex = new RegExp(partesRegex.join('|'), 'gi');

  return text
    .split(regex)
    .map(x => clean(x))
    .filter(Boolean);
}

function textoTemPluralConfigurado(value, config) {
  const text = normalizeKey(value);

  if (!text) return false;

  const palavrasPlural = getArrayConfig(config, 'multiplos_caes.palavras_plural');

  if (!palavrasPlural.length) {
    return false;
  }

  const tokens = text.split(/\s+/).filter(Boolean);
  const pluralSet = new Set(palavrasPlural.map(normalizeKey).filter(Boolean));

  return tokens.some(token => pluralSet.has(token));
}

function valoresPorPaths(root, paths) {
  return paths
    .map(path => getPath(root, path))
    .map(value => clean(value))
    .filter(Boolean);
}

function detectaMultiplosCaes(root, config) {
  const camposListaJson = getArrayConfig(config, 'multiplos_caes.campos_lista_json');

  for (const path of camposListaJson) {
    const value = parsePossivelJson(getPath(root, path));
    if (listaTemMaisDeUmItemPreenchido(value)) {
      return true;
    }
  }

  const camposQuantidade = getArrayConfig(config, 'multiplos_caes.campos_quantidade');
  const quantidade = getPrimeiroNumeroValido(
    camposQuantidade.map(path => getPath(root, path))
  );

  if (quantidade !== null && quantidade > 1) {
    return true;
  }

  const camposTexto = getArrayConfig(config, 'multiplos_caes.campos_texto');
  const valoresTexto = valoresPorPaths(root, camposTexto);

  const camposTextoComMaisDeUmValor = valoresTexto.some(value => {
    return splitTextoPorConfig(value, config).length > 1;
  });

  if (camposTextoComMaisDeUmValor) {
    return true;
  }

  const camposObservacao = getArrayConfig(config, 'multiplos_caes.campos_observacao');
  const valoresObservacao = valoresPorPaths(root, camposObservacao);

  const observacaoSugereMultiplos = valoresObservacao.some(value => {
    return (
      splitTextoPorConfig(value, config).length > 1 ||
      textoTemPluralConfigurado(value, config)
    );
  });

  return observacaoSugereMultiplos;
}

function montaLinhasPetNotaPrivada(root, config, multiplosCaes) {
  const labels = getObjectConfig(config, 'nota_privada_pet.labels');

  const labelPet = multiplosCaes
    ? clean(labels.pet_plural)
    : clean(labels.pet_singular);

  const labelIdade = multiplosCaes
    ? clean(labels.idade_plural)
    : clean(labels.idade_singular);

  const labelRaca = multiplosCaes
    ? clean(labels.raca_plural)
    : clean(labels.raca_singular);

  const resumoLead = root.resumo_lead || {};
  const resumoRepasse = root.resumo_interno_repasse || {};

  const perfilComportamental = pick(
    resumoRepasse.cao_perfil_comportamental,
