delete resumoRepasse.cao_reativo;

/*
  ==================================================
  Múltiplos cães
  ==================================================
*/

const root = {
  inputs,
  message,
  chatwoot,
  lead,
  memory,
  resumo_lead: resumoLead,
  resumo_interno_repasse: resumoRepasse
};

const multiplosCaes = detectaMultiplosCaes(root, config);

/*
  ==================================================
  Atualiza inputs finais
  ==================================================
*/

inputs.status_lead = statusFinal;
inputs.ultima_intencao = ultimaIntencao;
inputs.evento_sistema = eventoFinal;

inputs.deve_repassar_humano = true;
inputs.motivo_repasse = motivoRepasse;

inputs.deve_enviar_guia = false;
inputs.deve_solicitar_pagamento = false;
inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.deve_encerrar_conversa = false;

inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.comprovante_recebido = comprovanteRecebido;
inputs.tipo_comprovante = resumoRepasse.tipo_comprovante;

inputs.resumo_lead = resumoLead;
inputs.resumo_interno_repasse = resumoRepasse;
inputs.mensagens_resposta = message.mensagens_resposta;
inputs.multiplos_caes = multiplosCaes;

/*
  ==================================================
  Labels finais via config
  ==================================================
*/

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

const labelsRemover = getArrayConfig(config, 'repasse_humano_operacional.labels_remover')
  .map(labelRef => resolveLabel(labelRef, labelsConfig));

const removeSet = new Set(labelsRemover);
let labelsFinal = labelsAtuais.filter(label => !removeSet.has(label));

const labelsAdicionar = getArrayConfig(config, 'repasse_humano_operacional.labels_adicionar')
  .map(labelRef => resolveLabel(labelRef, labelsConfig));

labelsFinal.push(...labelsAdicionar);

const servico = normalizeKey(resumoLead.servico_interesse);
const labelsPorServico = getObjectConfig(config, 'repasse_humano_operacional.labels_por_servico');
const labelsServico = Array.isArray(labelsPorServico[servico]) ? labelsPorServico[servico] : [];

labelsFinal.push(
  ...labelsServico.map(labelRef => resolveLabel(labelRef, labelsConfig))
);

labelsFinal = unique(labelsFinal);

/*
  ==================================================
  Nota privada
  ==================================================
*/

const linhasPet = montaLinhasPetNotaPrivada(root, config, multiplosCaes);

const notaPrivada = [
  getStringConfig(config, 'repasse_humano_operacional.nota_titulo'),
  '',
  `Motivo: ${motivoRepasse || 'não informado'}`,
  `Status final: ${statusFinal || 'não informado'}`,
  `Última intenção: ${ultimaIntencao || 'não informada'}`,
  `Evento: ${eventoFinal || 'não informado'}`,
  '',
  `Tutor: ${pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name) || 'não informado'}`,
  `Telefone: ${pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone) || 'não informado'}`,
  '',
  ...linhasPet,
  '',
  `${clean(notaLabels.unidade)}: ${pick(resumoRepasse.unidade_preferida, resumoLead.unidade_preferida) || 'não informada'}`,
  `${clean(notaLabels.data_hora_avaliacao)}: ${pick(resumoRepasse.data_hora_avaliacao, resumoLead.data_hora_avaliacao, inputs.data_hora_avaliacao) || 'não informada'}`,
  `${clean(notaLabels.comprovante_recebido)}: ${comprovanteRecebido ? 'sim' : 'não'}`,
  `${clean(notaLabels.tipo_comprovante)}: ${resumoRepasse.tipo_comprovante || 'não informado'}`
].join('\n');

/*
  ==================================================
  Opções para subworkflow
  ==================================================
*/

const shouldReply = item.should_reply !== false;

const enviaChatwoot =
  shouldReply === true &&
  cleanAnswer.length > 0 &&
  repasseConfig.envia_chatwoot !== false;

const opcoes = {
  ...opcoesOriginais,
  acionar_humano: true,

  rota_origem: item.switch_final?.rota || 'REPASSAR HUMANO',
  motivo_rota: item.switch_final?.motivo || motivoRepasse,

  envia_chatwoot: enviaChatwoot,
  atualizar_contact_summary: repasseConfig.atualizar_contact_summary !== false,

  gravar_memoria: repasseConfig.gravar_memoria !== false,
  gravar_historico: repasseConfig.gravar_historico !== false,

  atualiza_labels: repasseConfig.atualiza_labels !== false,
  labels_new: labelsFinal,

  adicionar_nota_privada: repasseConfig.adicionar_nota_privada !== false,
  nota_privada_texto: notaPrivada,

  pula_verificao_ultima_mensagem: repasseConfig.pula_verificao_ultima_mensagem === true,

  tipo_registro_historico: getStringConfig(config, 'repasse_humano_operacional.tipo_registro_historico'),
  origem_registro_historico: getStringConfig(config, 'repasse_humano_operacional.origem_registro_historico'),

  finalizador: getStringConfig(config, 'repasse_humano_operacional.finalizador'),
  status_final: statusFinal,
  motivo_repasse: motivoRepasse,
  responsavel_humano: responsavelHumano,
  multiplos_caes: multiplosCaes
};

return [
  {
    json: {
      message,
      lead,
      chatwoot,
      memory,
      inputs,
      opcoes,

      config_bruna: config,
      should_reply: shouldReply,
      motivo_bloqueio_envio: item.motivo_bloqueio_envio || '',

      guard_pos_bruna: item.guard_pos_bruna || {},
      switch_final: item.switch_final || {},

      regras_raca: item.regras_raca || inputs.regras_raca || {},
      run_mode: item.run_mode || 'prod',
      prompt_version: item.prompt_version || 'bruna_v5_prepara_repasse_humano',

      debug_context: {
        ...(item.debug_context || {}),
        prepara_repasse_humano_version: 'v5_8_config_multi_caes_nota_comportamento',
        status_final: statusFinal,
        evento_final: eventoFinal,
        ultima_intencao: ultimaIntencao,
        motivo_repasse: motivoRepasse,
        responsavel_humano: responsavelHumano,
        envia_chatwoot: enviaChatwoot,
        labels_final: labelsFinal,
        comprovante_recebido: comprovanteRecebido,
        tipo_comprovante: resumoRepasse.tipo_comprovante,
        multiplos_caes: multiplosCaes,
        nota_tem_perfil_comportamental: true,
        nota_tem_observacoes_comportamento: true,
        nota_tem_observacoes_gerais: true
      }
    }
  }
];

const item = $input.first().json || {};

const inputs = item.inputs || {};
const message = item.message || {};
const guard = item.guard_pos_bruna || {};

function clean(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value).trim();
}

function isTrue(value) {
  return value === true;
}

function isIn(value, list) {
  return list.includes(clean(value));
}

function defineRoute(route, motivo) {
  return {
    rota: route,
    motivo,
    versao: 'switch_final_v4_2'
  };
}

// ======================================================
// BLOQUEIO GLOBAL DE RESPOSTA
// ======================================================

if (item.should_reply !== true) {
  return [
    {
      json: {
        ...item,
        switch_final: defineRoute(
          'NAO RESPONDER',
          item.motivo_bloqueio_envio || 'should_reply_false'
        )
      }
    }
  ];
}

const statusLead = clean(inputs.status_lead);
const ultimaIntencao = clean(inputs.ultima_intencao);
const eventoSistema = clean(inputs.evento_sistema);
const statusPagamento = clean(inputs.status_pagamento);
const motivoRepasse = clean(inputs.motivo_repasse);

const hasAttachment = message.has_attachment === true;

const guardBloqueouPix =
  inputs.guard_pix_bloqueado === true ||
  guard.aprovado === false;

const statusEncerramento = [
  'ENCERRADO_NAO_PERFIL',
  'ENCERRADO_SEM_RESPOSTA',
  'ENCERRADO'
];

const statusNaoPodePedirPix = [
  'TRANSFERIDO_FLAVIA',
  'ENCERRADO_NAO_PERFIL',
  'ENCERRADO_SEM_RESPOSTA',
  'ENCERRADO',
  'COMPROVANTE_RECEBIDO'
];

const isEncerramento = [
  isTrue(inputs.deve_encerrar_conversa),
  isIn(statusLead, statusEncerramento),
  eventoSistema === 'CONVERSA_ENCERRADA'
].includes(true);

if (isEncerramento) {
  return [
    {
      json: {
        ...item,
        switch_final: defineRoute(
          'ENCERRAR CONVERSA',
          'encerramento_explicito_ou_status_final'
        )
      }
    }
  ];
}

const isComprovantePorEventoAtual =
  eventoSistema === 'COMPROVANTE_IDENTIFICADO';

const isComprovantePorAnexoAtual =
  hasAttachment === true &&
  [
    statusLead === 'AGUARDANDO_PAGAMENTO',
    statusPagamento === 'aguardando_pagamento',
    eventoSistema === 'ANEXO_RECEBIDO'
  ].includes(true);

const isComprovanteRecebido = [
  isComprovantePorEventoAtual,
  isComprovantePorAnexoAtual
].includes(true);

if (isComprovanteRecebido) {
  return [
    {
      json: {
        ...item,
        switch_final: defineRoute(
          'COMPROVANTE RECEBIDO',
          'comprovante_identificado_no_turno_atual'
        )
      }
    }
  ];
}

const isRepasseHumanoConfirmado =
  inputs.deve_repassar_humano === true &&
  [
    statusLead === 'TRANSFERIDO_FLAVIA',
    eventoSistema === 'REPASSE_FLAVIA',
    motivoRepasse === 'lead_confirmou_atendimento_humano'
  ].includes(true);

if (isRepasseHumanoConfirmado) {
  return [
    {
      json: {
        ...item,
        switch_final: defineRoute(
          'REPASSAR HUMANO',
          'lead_confirmou_atendimento_humano'
        )
      }
    }
  ];
}

const querSolicitarPagamento = [
  inputs.deve_solicitar_pagamento === true,
  eventoSistema === 'PIX_SOLICITADO'
].includes(true);

const pagamentoBloqueado = [
  guardBloqueouPix,
  ultimaIntencao === 'PEDIU_VALOR',
  ultimaIntencao === 'PEDIU_HUMANO',
  isIn(statusLead, statusNaoPodePedirPix),
  statusPagamento === 'comprovante_recebido'
].includes(true);

if (querSolicitarPagamento === true && pagamentoBloqueado === false) {
  return [
    {
      json: {
        ...item,
        switch_final: defineRoute(
          'SOLICITAR PAGAMENTO',
          'pix_liberado_por_saida_da_bruna_e_guard'
        )
      }
    }
  ];
}

const isEnviarGuia = [
  inputs.deve_enviar_guia === true,
  eventoSistema === 'GUIA_ENVIADO'
].includes(true);

if (isEnviarGuia) {
  return [
    {
      json: {
        ...item,
        switch_final: defineRoute(
          'ENVIAR GUIA',
          'envio_de_guia_solicitado'
        )
      }
    }
  ];
}

return [
  {
    json: {
      ...item,
      switch_final: defineRoute(
        'PREPARA CHATWOOT',
        'rota_padrao_resposta_normal'
      )
    }
  }
];

/*
  ==================================================
  GUARD E FINALIZA BRUNA
  ==================================================

  Entra logo depois do NORMALIZA BRUNA.

  Faz:
  1. preserva estrutura completa do fluxo;
  2. normaliza mensagens finais;
  3. respeita should_reply=false;
  4. executa guard pós-Bruna;
  5. monta message.clean_answer;
  6. preserva config_bruna para os prepares;
  7. mantém inputs como fonte principal para o DEFINE ROTA SWITCH FINAL.

  Saída principal:
  - inputs
  - message
  - chatwoot
  - lead
  - memory
  - config_bruna
  - should_reply
  - motivo_bloqueio_envio
  - guard_pos_bruna
*/

const allItems = $input.all();

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function clone(value) {
  if (value === undefined || value === null) return value;
  return JSON.parse(JSON.stringify(value));
}

function ensureObject(value) {
  return isObject(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asBooleanStrict(value) {
  return value === true;
}

function cleanText(value) {
  return String(value || '')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeText(value) {
  return cleanText(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^\w\s$]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeMessages(messages, maxMessages, maxChars) {
  return asArray(messages)
    .map(cleanText)
    .filter(Boolean)
    .slice(0, maxMessages)
    .map((msg) => {
      if (!maxChars || msg.length <= maxChars) return msg;
      return msg.slice(0, maxChars).trim();
    })
    .filter(Boolean);
}

function has(regex, text) {
  return regex.test(text);
}

function respostaTem(regex, text) {
  return regex.test(text);
}

function isSimpleAck(text) {
  const t = normalizeText(text);

  return [
    'ok',
    'okay',
    'certo',
    'ta bom',
    'tudo bem',
    'obrigado',
    'obrigada',
    'valeu',
    'beleza',
    'blz',
    'show',
    'perfeito',
    'joia',
    'sim',
    'combinado'
  ].includes(t);
}

function enumValue(value, allowed, fallback) {
  const v = cleanText(value);
  return allowed.includes(v) ? v : fallback;
}

function normalizeTipoComprovante(value, comprovanteRecebido) {
  if (comprovanteRecebido !== true) return 'nao_informado';

  const v = normalizeText(value);

  if (['imagem', 'image', 'foto'].includes(v)) return 'imagem';
  if (v === 'pdf') return 'pdf';
  if (['print', 'print banco', 'print_banco', 'screenshot'].includes(v)) return 'print_banco';

  return 'nao_informado';
}

function normalizeCastrado(value) {
  const v = normalizeText(value);

  if (['sim', 'castrado', 'castrada', 'castrados', 'castradas'].includes(v)) {
    return 'sim';
  }

  if (['nao', 'nao castrado', 'nao castrada', 'nao_castrado', 'nao_castrada'].includes(v)) {
    return 'nao';
  }

  return 'nao_informado';
}

function normalizePerfilComportamental(value) {
  return enumValue(
    value,
    [
      'nao_informado',
      'tranquilo',
      'sociavel',
      'seletivo',
      'reativo_leve',
      'reativo_alto',
      'agressivo'
    ],
    'nao_informado'
  );
}

return allItems.map((inputItem) => {
  const item = clone(inputItem.json) || {};

  const inputs = ensureObject(item.inputs);
  const message = ensureObject(item.message);
  const chatwoot = ensureObject(item.chatwoot);
  const lead = ensureObject(item.lead);
  const memory = ensureObject(item.memory);
  const configBruna = ensureObject(item.config_bruna);

  const guardConfig = ensureObject(configBruna.guardrails_pos_bruna);
  const microcopy = ensureObject(configBruna.microcopy);

  const maxMessages = Number(
    guardConfig.max_mensagens ||
    microcopy.max_mensagens ||
    3
  );

  const maxChars = Number(
    guardConfig.max_chars_por_mensagem ||
    microcopy.max_chars_por_mensagem ||
    420
  );

  inputs.resumo_lead = ensureObject(inputs.resumo_lead);
  inputs.resumo_interno_repasse = ensureObject(inputs.resumo_interno_repasse);

  /*
    ==================================================
    Normalizações finais obrigatórias
    ==================================================
  */

  inputs.deve_repassar_humano = asBooleanStrict(inputs.deve_repassar_humano);
  inputs.deve_enviar_guia = asBooleanStrict(inputs.deve_enviar_guia);
  inputs.deve_solicitar_pagamento = asBooleanStrict(inputs.deve_solicitar_pagamento);
  inputs.deve_encerrar_conversa = asBooleanStrict(inputs.deve_encerrar_conversa);

  inputs.deve_consultar_agenda = false;
  inputs.deve_criar_pre_reserva = false;

  inputs.pre_reserva_criada = false;
  inputs.data_hora_avaliacao = '';
  inputs.data_hora_pre_reserva = '';

  inputs.resumo_lead.data_hora_avaliacao = '';
  inputs.resumo_lead.data_hora_pre_reserva = '';
  inputs.resumo_lead.pre_reserva_criada = false;

  inputs.resumo_interno_repasse.data_hora_avaliacao = '';

  inputs.resumo_lead.cao_castrado = normalizeCastrado(inputs.resumo_lead.cao_castrado);
  inputs.resumo_interno_repasse.cao_castrado = normalizeCastrado(inputs.resumo_interno_repasse.cao_castrado);

  inputs.resumo_lead.cao_perfil_comportamental = normalizePerfilComportamental(
    inputs.resumo_lead.cao_perfil_comportamental
  );

  inputs.resumo_interno_repasse.cao_perfil_comportamental = normalizePerfilComportamental(
    inputs.resumo_interno_repasse.cao_perfil_comportamental
  );

  inputs.resumo_lead.tipo_comprovante = normalizeTipoComprovante(
    inputs.resumo_lead.tipo_comprovante,
    inputs.resumo_lead.comprovante_recebido === true
  );

  inputs.resumo_interno_repasse.tipo_comprovante = normalizeTipoComprovante(
    inputs.resumo_interno_repasse.tipo_comprovante,
    inputs.resumo_interno_repasse.comprovante_recebido === true
  );

  inputs.tipo_comprovante = normalizeTipoComprovante(
    inputs.tipo_comprovante,
    inputs.comprovante_recebido === true
  );

  /*
    Remove campos legados se algum modelo/node antigo deixar passar.
  */
  delete inputs.resumo_lead.cao_sociavel;
  delete inputs.resumo_lead.cao_reativo;
  delete inputs.resumo_interno_repasse.cao_sociavel;
  delete inputs.resumo_interno_repasse.cao_reativo;

  /*
    ==================================================
    Mensagens finais
    ==================================================
  */

  const mensagensResposta = normalizeMessages(
    inputs.mensagens_resposta,
    maxMessages,
    maxChars
  );

  const cleanAnswer = mensagensResposta.join('\n\n').trim();

  inputs.mensagens_resposta = mensagensResposta;
  message.mensagens_resposta = mensagensResposta;
  message.clean_answer = cleanAnswer;

  /*
    ==================================================
    should_reply
    ==================================================
  */

  let shouldReply =
    item.should_reply === false
      ? false
      : cleanAnswer.length > 0;

  let motivoBloqueioEnvio = cleanText(item.motivo_bloqueio_envio);

  if (shouldReply !== true && !motivoBloqueioEnvio) {
    motivoBloqueioEnvio = 'should_reply_false_ou_sem_mensagem';
  }

  /*
    ==================================================
    Se já veio bloqueado, não reprova o guard por falta de pergunta.
    Apenas finaliza sem envio.
    ==================================================
  */

  if (shouldReply !== true) {
    return {
      json: {
        ...item,

        inputs: {
          ...inputs,
          mensagens_resposta: [],
          deve_enviar_guia: false,
          deve_solicitar_pagamento: false,
          deve_repassar_humano: false,
          motivo_repasse: '',
          deve_consultar_agenda: false,
          deve_criar_pre_reserva: false
        },

        message: {
          ...message,
          mensagens_resposta: [],
          clean_answer: ''
        },

        chatwoot,
        lead,
        memory,

        config_bruna: configBruna,

        agent_name: item.agent_name || 'Bruna',
        should_reply: false,
        motivo_bloqueio_envio: motivoBloqueioEnvio,

        guard_pos_bruna: {
          aprovado: true,
          erros: [],
          precisa_reprocessar: false,
          bloqueado_por_should_reply: true,
          motivo_bloqueio_envio: motivoBloqueioEnvio,
          sinais_detectados: {}
        },

        regras_raca: item.regras_raca || inputs.regras_raca || {},
        opcoes: item.opcoes || {},

        run_mode: item.run_mode || 'prod',
        prompt_version: item.prompt_version || 'bruna_v5_2_guard_finaliza',

        raw_bruna_output: item.raw_bruna_output || '',

        debug_context: {
          ...(item.debug_context || {}),
          guard_finaliza_version: 'v5_2_unificado',
          should_reply: false,
          motivo_bloqueio_envio: motivoBloqueioEnvio
        }
      }
    };
  }

  /*
    ==================================================
    Guard pós-Bruna
    ==================================================
  */

  const textoLead = normalizeText(
    message.current_lead_block_text ||
    message.content ||
    ''
  );

  const mensagens = normalizeText(mensagensResposta.join('\n'));
  const ultimaMensagem = cleanText(mensagensResposta[mensagensResposta.length - 1] || '');

  const resumo = inputs.resumo_lead || {};
  const erros = [];

  const conversaContinua =
    inputs.deve_encerrar_conversa !== true &&
    inputs.deve_repassar_humano !== true &&
    inputs.status_lead !== 'ENCERRADO_NAO_PERFIL' &&
    inputs.status_lead !== 'ENCERRADO_SEM_RESPOSTA' &&
    inputs.status_lead !== 'ENCERRADO' &&
    inputs.status_lead !== 'TRANSFERIDO_FLAVIA';

  const ultimaTemPerguntaOuConvite =
    /[?？]\s*$/.test(ultimaMensagem) ||
    /(me diga|me fala|me conta|pode me mandar|pode responder|me confirma|envia por aqui|mande por aqui|chama por aqui|me avisa|posso te explicar|quer que eu|se quiser|posso ajudar)/i.test(ultimaMensagem);

  /*
    Intenções do lead
  */

  const pediuPreco = has(/valor|preço|preco|mensal|mensalidade|diária|diaria|pacote|plano|quanto|custa|custaria|tabela/, textoLead);

  const pediuMensal = has(/mensal|mensalidade|plano mensal|planos mensais|pacote mensal/, textoLead);

  const pediuLocalizacaoGenerica = has(/onde fica|onde e|endereco|localizacao|qual unidade|unidades|fica onde|bairro/, textoLead);

  const pediuAmaralinaEspecifico = has(/amaralina/, textoLead);
  const pediuPatamaresEspecifico = has(/patamares|auauzin/, textoLead);

  const pediuLocalizacao =
    pediuLocalizacaoGenerica ||
    pediuAmaralinaEspecifico ||
    pediuPatamaresEspecifico;

  const pediuVisitaOuMaterial = has(/visita|visitar|conhecer|estrutura|fotos|foto|material|guia|site|instagram|canal/, textoLead);

  /*
    Sinais de resposta da Bruna
  */

  const respondeuPreco =
    respostaTem(/r\$|\breais\b|valor|preco|diaria|mensal|plano|pacote|avulsa|avulso/, mensagens);

  const respondeuMensal =
    respostaTem(/mensal|mensalidade|plano|planos|frequencia|vez(?:es)? por semana|1x|2x|3x|4x|5x/, mensagens);

  const citouAmaralina = respostaTem(/amaralina|manoel dias/, mensagens);
  const citouPatamares = respostaTem(/patamares|auauzin|pinto de aguiar/, mensagens);

  const respondeuLocalizacaoGenerica = citouAmaralina && citouPatamares;
  const respondeuAmaralinaEspecifico = citouAmaralina;
  const respondeuPatamaresEspecifico = citouPatamares;

  const respondeuVisitaOuMaterial =
    respostaTem(/conhecer|visita|visitar|estrutura|camera|fotos|foto|material|guia|site|instagram|redes sociais/, mensagens);

  const falouPagamento =
    respostaTem(/pix|pagamento|comprovante|pagar|taxa/, mensagens);

  /*
    Validações
  */

  if (pediuPreco && !respondeuPreco) {
    erros.push('Lead pediu preço, mas a Bruna não respondeu valor, plano, diária, pacote ou referência objetiva de preço.');
  }

  if (pediuMensal && !respondeuMensal) {
    erros.push('Lead pediu mensalidade/plano, mas a Bruna não respondeu sobre planos mensais ou frequência semanal.');
  }

  if (pediuLocalizacaoGenerica && !respondeuLocalizacaoGenerica) {
    erros.push('Lead pediu localização genérica, mas a Bruna não citou as duas unidades.');
  }

  if (pediuAmaralinaEspecifico && !pediuLocalizacaoGenerica && !respondeuAmaralinaEspecifico) {
    erros.push('Lead perguntou sobre Amaralina, mas a Bruna não respondeu Amaralina.');
  }

  if (pediuPatamaresEspecifico && !pediuLocalizacaoGenerica && !respondeuPatamaresEspecifico) {
    erros.push('Lead perguntou sobre Patamares/AuAuzin, mas a Bruna não respondeu Patamares/AuAuzin.');
  }

  if (pediuVisitaOuMaterial && !respondeuVisitaOuMaterial) {
    erros.push('Lead pediu visita, fotos, material ou canal para conhecer melhor, mas a Bruna não respondeu essa dúvida.');
  }

  if (pediuVisitaOuMaterial && falouPagamento && !respondeuVisitaOuMaterial) {
    erros.push('Lead pediu visita/material, mas a Bruna voltou para pagamento sem responder a dúvida.');
  }

  if (conversaContinua && !ultimaTemPerguntaOuConvite) {
    erros.push('Conversa continua, mas a última mensagem não termina com pergunta útil nem convite claro para próximo passo.');
  }

  const reconheceuCastracaoNoTexto =
    respostaTem(/confirm(?:ar|ado|ada|ei|ou)? .*castra|castracao confirmada|castrado|castrada|ele e castrado|ela e castrada/, mensagens);

  if (
    resumo.cao_castrado === 'nao_informado' &&
    reconheceuCastracaoNoTexto
  ) {
    erros.push('A Bruna reconheceu castração no texto, mas resumo_lead.cao_castrado ficou nao_informado.');
  }

  const leadAceitouAvaliacao =
    /quero seguir|pode mandar.*pix|manda.*pix|vou pagar|quero avaliacao|pode agendar|vamos fazer/.test(textoLead);

  if (
    falouPagamento &&
    inputs.deve_solicitar_pagamento === true &&
    !leadAceitouAvaliacao &&
    pediuPreco
  ) {
    erros.push('Bruna sinalizou pagamento/PIX em turno de preço sem aceite claro de avaliação.');
  }

  /*
    Bloqueio de PIX por guard.
  */

  if (erros.length > 0 && inputs.deve_solicitar_pagamento === true) {
    inputs.deve_solicitar_pagamento = false;
    inputs.evento_sistema = '';
    inputs.status_pagamento = 'nao_solicitado';
  }

  const guardAprovado = erros.length === 0;

  return {
    json: {
      ...item,

      inputs,

      message,
      chatwoot,
      lead,
      memory,

      config_bruna: configBruna,

      agent_name: item.agent_name || 'Bruna',
      should_reply: shouldReply,
      motivo_bloqueio_envio: motivoBloqueioEnvio,

      guard_pos_bruna: {
        aprovado: guardAprovado,
        erros,
        precisa_reprocessar: erros.length > 0,
        bloqueado_por_should_reply: false,
        sinais_detectados: {
          pediuPreco,
          pediuMensal,
          pediuLocalizacao,
          pediuLocalizacaoGenerica,
          pediuAmaralinaEspecifico,
          pediuPatamaresEspecifico,
          pediuVisitaOuMaterial,
          respondeuPreco,
          respondeuMensal,
          respondeuLocalizacaoGenerica,
          respondeuVisitaOuMaterial,
          conversaContinua,
          falouPagamento
        }
      },

      regras_raca: item.regras_raca || inputs.regras_raca || {},
      opcoes: item.opcoes || {},

      run_mode: item.run_mode || 'prod',
      prompt_version: item.prompt_version || 'bruna_v5_2_guard_finaliza',

      raw_bruna_output: item.raw_bruna_output || '',

      debug_context: {
        ...(item.debug_context || {}),
        guard_finaliza_version: 'v5_2_unificado',
        should_reply: shouldReply,
        motivo_bloqueio_envio: motivoBloqueioEnvio,
        guard_aprovado: guardAprovado,
        guard_erros_count: erros.length
      }
    }
  };
});

const item = $input.first().json || {};

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function clean(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeKey(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^\w\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function pick(...values) {
  for (const value of values) {
    const text = clean(value);
    if (text) return text;
  }

  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => clean(x)).filter(Boolean);
  }

  if (typeof value === 'string') {
    const text = value.trim();

    if (!text) return [];

    try {
      const parsed = JSON.parse(text);
      if (Array.isArray(parsed)) {
        return parsed.map(x => clean(x)).filter(Boolean);
      }
    } catch (e) {}

    return text
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(values) {
  return [...new Set(values.map(x => clean(x)).filter(Boolean))];
}

function getPath(root, path) {
  const parts = clean(path).split('.').filter(Boolean);
  let current = root;

  for (const part of parts) {
    if (current === undefined || current === null) return undefined;
    current = current[part];
  }

  return current;
}

function getConfig(config, path, fallback) {
  const value = getPath(config, path);
  return value === undefined || value === null ? fallback : value;
}

function getArrayConfig(config, path) {
  const value = getConfig(config, path, []);
  return Array.isArray(value) ? value : [];
}

function getObjectConfig(config, path) {
  const value = getConfig(config, path, {});
  return isObject(value) ? value : {};
}

function getStringConfig(config, path, fallback = '') {
  const value = getConfig(config, path, fallback);
  const text = clean(value);
  return text || fallback;
}

function escapeRegExp(value) {
  return clean(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function parsePossivelJson(value) {
  if (Array.isArray(value) || isObject(value)) return value;

  const text = clean(value);
  if (!text) return null;

  try {
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

function listaTemMaisDeUmItemPreenchido(value) {
  if (!Array.isArray(value)) return false;

  const preenchidos = value.filter(item => {
    if (isObject(item)) {
      return Object.values(item).some(v => clean(v));
    }

    return clean(item);
  });

  return preenchidos.length > 1;
}

function getPrimeiroNumeroValido(values) {
  for (const value of values) {
    const text = clean(value);

    if (!text) continue;

    const number = Number(text.replace(',', '.'));

    if (Number.isFinite(number)) {
      return number;
    }
  }

  return null;
}

function normalizeByConfig(value, normalizacaoConfig) {
  const text = normalizeKey(value);
  const fallback = clean(normalizacaoConfig.fallback);
  const permitidos = Array.isArray(normalizacaoConfig.permitidos)
    ? normalizacaoConfig.permitidos.map(clean)
    : [];

  const aliases = isObject(normalizacaoConfig.aliases)
    ? normalizacaoConfig.aliases
    : {};

  for (const [canonical, aliasList] of Object.entries(aliases)) {
    const aliasesNormalizados = Array.isArray(aliasList)
      ? aliasList.map(normalizeKey)
      : [];

    if (aliasesNormalizados.includes(text)) {
      return canonical;
    }
  }

  const raw = clean(value);
  if (permitidos.includes(raw)) {
    return raw;
  }

  return fallback;
}

function normalizeTipoComprovante(value, comprovanteRecebido, config) {
  const tipoConfig = getObjectConfig(config, 'normalizacao_pet.tipo_comprovante');

  if (comprovanteRecebido !== true) {
    return getStringConfig(
      config,
      'normalizacao_pet.tipo_comprovante.quando_nao_recebido',
      'nao_informado'
    );
  }

  return normalizeByConfig(value, tipoConfig);
}

function splitTextoPorConfig(value, config) {
  const text = clean(value);

  if (!text) return [];

  const separadores = getArrayConfig(config, 'multiplos_caes.separadores_texto');
  const conectores = getArrayConfig(config, 'multiplos_caes.conectores_texto');

  const tokensConfigurados = unique([
    ...separadores,
    ...conectores
  ]).map(token => token === '\\n' ? '\n' : token);

  if (!tokensConfigurados.length) {
    return [text];
  }

  const partesRegex = tokensConfigurados
    .map(token => escapeRegExp(token))
    .filter(Boolean);

  if (!partesRegex.length) {
    return [text];
  }

  const regex = new RegExp(partesRegex.join('|'), 'gi');

  return text
    .split(regex)
    .map(x => clean(x))
    .filter(Boolean);
}

function textoTemPluralConfigurado(value, config) {
  const text = normalizeKey(value);

  if (!text) return false;

  const palavrasPlural = getArrayConfig(config, 'multiplos_caes.palavras_plural');

  if (!palavrasPlural.length) {
    return false;
  }

  const tokens = text.split(/\s+/).filter(Boolean);
  const pluralSet = new Set(palavrasPlural.map(normalizeKey).filter(Boolean));

  return tokens.some(token => pluralSet.has(token));
}

function valoresPorPaths(root, paths) {
  return paths
    .map(path => getPath(root, path))
    .map(value => clean(value))
    .filter(Boolean);
}

function detectaMultiplosCaes(root, config) {
  const camposListaJson = getArrayConfig(config, 'multiplos_caes.campos_lista_json');

  for (const path of camposListaJson) {
    const value = parsePossivelJson(getPath(root, path));
    if (listaTemMaisDeUmItemPreenchido(value)) {
      return true;
    }
  }

  const camposQuantidade = getArrayConfig(config, 'multiplos_caes.campos_quantidade');
  const quantidade = getPrimeiroNumeroValido(
    camposQuantidade.map(path => getPath(root, path))
  );

  if (quantidade !== null && quantidade > 1) {
    return true;
  }

  const camposTexto = getArrayConfig(config, 'multiplos_caes.campos_texto');
  const valoresTexto = valoresPorPaths(root, camposTexto);

  const camposTextoComMaisDeUmValor = valoresTexto.some(value => {
    return splitTextoPorConfig(value, config).length > 1;
  });

  if (camposTextoComMaisDeUmValor) {
    return true;
  }

  const camposObservacao = getArrayConfig(config, 'multiplos_caes.campos_observacao');
  const valoresObservacao = valoresPorPaths(root, camposObservacao);

  const observacaoSugereMultiplos = valoresObservacao.some(value => {
    return (
      splitTextoPorConfig(value, config).length > 1 ||
      textoTemPluralConfigurado(value, config)
    );
  });

  return observacaoSugereMultiplos;
}

function montaLinhasPetNotaPrivada(root, config, multiplosCaes) {
  const labels = getObjectConfig(config, 'nota_privada_pet.labels');

  const labelPet = multiplosCaes
    ? clean(labels.pet_plural)
    : clean(labels.pet_singular);

  const labelIdade = multiplosCaes
    ? clean(labels.idade_plural)
    : clean(labels.idade_singular);

  const labelRaca = multiplosCaes
    ? clean(labels.raca_plural)
    : clean(labels.raca_singular);

  const resumoLead = root.resumo_lead || {};
  const resumoRepasse = root.resumo_interno_repasse || {};

  const perfilComportamental = pick(
    resumoRepasse.cao_perfil_comportamental,
    resumoLead.cao_perfil_comportamental
  );

  const observacoesComportamento = pick(
    resumoRepasse.cao_comportamento_observacoes,
    resumoLead.cao_comportamento_observacoes
  );

  const observacoesGerais = pick(
    resumoRepasse.observacoes,
    resumoLead.observacoes
  );

  return [
    `${labelPet}: ${pick(resumoRepasse.cao_nome, resumoLead.cao_nome) || 'não informado'}`,
    `${labelIdade}: ${pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto) || 'não informada'}`,
    `${labelRaca}: ${pick(resumoRepasse.cao_raca, resumoLead.cao_raca) || 'não informada'}`,
    `${clean(labels.porte)}: ${pick(resumoRepasse.cao_porte, resumoLead.cao_porte) || 'não informado'}`,
    `${clean(labels.sexo)}: ${pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo) || 'não informado'}`,
    `${clean(labels.castrado)}: ${pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado) || 'não informado'}`,
    `${clean(labels.servico)}: ${pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse) || 'não informado'}`,
    `${clean(labels.perfil_comportamental)}: ${perfilComportamental || 'não informado'}`,
    `${clean(labels.comportamento_observacoes)}: ${observacoesComportamento || 'sem observações de comportamento'}`,
    `${clean(labels.observacoes_gerais)}: ${observacoesGerais || 'sem observações gerais'}`,
    `${clean(labels.multiplos_caes)}: ${multiplosCaes ? 'sim' : 'não'}`
  ];
}

function resolveLabel(labelRef, labelsConfig) {
  const ref = clean(labelRef);
  if (!ref) return '';

  return clean(labelsConfig[ref]) || ref;
}

