  `${clean(notaLabels.status_lead)}: ${inputs.status_lead || 'não informado'}`,
  `${clean(notaLabels.ultima_intencao)}: ${inputs.ultima_intencao || 'não informada'}`,
  `${clean(notaLabels.evento_sistema)}: ${eventoSistemaFinal || 'não informado'}`,
  `${clean(notaLabels.rota)}: ${item.switch_final?.rota || 'NAO RESPONDER'}`,
  `${clean(notaLabels.motivo_rota)}: ${item.switch_final?.motivo || 'não informado'}`,
  `${clean(notaLabels.should_reply)}: false`,
  '',
  `Tutor: ${pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name) || 'não informado'}`,
  `Telefone: ${pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone) || 'não informado'}`,
  '',
  ...linhasPet
].join('\n');

/*
  ==================================================
  Opções para subworkflow
  ==================================================
*/

const opcoes = {
  ...opcoesOriginais,
  acionar_humano: false,

  rota_origem: item.switch_final?.rota || 'NAO RESPONDER',
  motivo_rota: item.switch_final?.motivo || motivoBloqueio,

  envia_chatwoot: false,
  atualizar_contact_summary: naoResponderConfig.atualizar_contact_summary === true,

  gravar_memoria: naoResponderConfig.gravar_memoria === true,
  gravar_historico: naoResponderConfig.gravar_historico !== false,

  atualiza_labels: naoResponderConfig.atualiza_labels === true,
  labels_new: labelsFinal,

  adicionar_nota_privada: naoResponderConfig.adicionar_nota_privada === true,
  nota_privada_texto: notaPrivada,

  pula_verificao_ultima_mensagem: naoResponderConfig.pula_verificao_ultima_mensagem !== false,

  tipo_registro_historico: getStringConfig(config, 'nao_responder_operacional.tipo_registro_historico'),
  origem_registro_historico: getStringConfig(config, 'nao_responder_operacional.origem_registro_historico'),

  finalizador: getStringConfig(config, 'nao_responder_operacional.finalizador'),
  motivo_bloqueio_envio: motivoBloqueio,
  status_final: inputs.status_lead || '',
  evento_final: eventoSistemaFinal,
  multiplos_caes: multiplosCaes
};

return [
  {
    json: {
      message,
      lead,
      chatwoot,
      memory,
      inputs,
      opcoes,

      config_bruna: config,
      should_reply: false,
      motivo_bloqueio_envio: motivoBloqueio,

      guard_pos_bruna: item.guard_pos_bruna || {},
      pre_bruna_guard: item.pre_bruna_guard || {},
      switch_final: item.switch_final || {},

      regras_raca: item.regras_raca || inputs.regras_raca || {},
      run_mode: item.run_mode || 'prod',
      prompt_version: item.prompt_version || 'bruna_v5_prepara_nao_responder',

      debug_context: {
        ...(item.debug_context || {}),
        prepara_nao_responder_version: 'v5_12_config_passivo_sem_envio',
        should_reply: false,
        motivo_bloqueio_envio: motivoBloqueio,
        envia_chatwoot: false,
        atualizar_contact_summary: opcoes.atualizar_contact_summary,
        gravar_memoria: opcoes.gravar_memoria,
        gravar_historico: opcoes.gravar_historico,
        atualiza_labels: opcoes.atualiza_labels,
        adicionar_nota_privada: opcoes.adicionar_nota_privada,
        labels_final: labelsFinal,
        multiplos_caes: multiplosCaes,
        nota_privada_montada: true,
        nota_privada_enviada: opcoes.adicionar_nota_privada
      }
    }
  }
];
